original_sparql:
PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?entity ?label
WHERE {
  VALUES ?entity { brick:Weather_Station brick:Energy_Usage_Sensor }
  ?entity rdfs:label ?label .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
SELECT ?zone
       ?zoneTempSensorTSID
       ?minTempSetpointTSID ?maxTempSetpointTSID
       ?tempSetpointTSID ?heatingTempSetpointTSID ?coolingTempSetpointTSID
       ?occupiedTempSetpointTSID ?unoccupiedTempSetpointTSID
       ?occupancySensorTSID ?occupancyCommandTSID
       ?vav ?damperTSID ?dischargeTempTSID ?reheatCommandTSID
WHERE {
    ?zone a brick:HVAC_Zone .

    OPTIONAL {
        ?zoneTempSensor a brick:Zone_Temperature_Sensor ;
                        brick:hasLocation ?zone ;
                        ref:hasTimeseriesId ?zoneTempSensorTSID .
    }
    OPTIONAL {
        ?minTempSetpoint a brick:Min_Temperature_Setpoint ;
                         brick:hasLocation ?zone ;
                         ref:hasTimeseriesId ?minTempSetpointTSID .
    }
    OPTIONAL {
        ?maxTempSetpoint a brick:Max_Temperature_Setpoint ;
                         brick:hasLocation ?zone ;
                         ref:hasTimeseriesId ?maxTempSetpointTSID .
    }
    OPTIONAL {
        ?tempSetpoint a brick:Temperature_Setpoint ;
                      brick:hasLocation ?zone ;
                      ref:hasTimeseriesId ?tempSetpointTSID .
    }
    OPTIONAL {
        ?heatingTempSetpoint a brick:Heating_Temperature_Setpoint ;
                             brick:hasLocation ?zone ;
                             ref:hasTimeseriesId ?heatingTempSetpointTSID .
    }
    OPTIONAL {
        ?coolingTempSetpoint a brick:Cooling_Temperature_Setpoint ;
                             brick:hasLocation ?zone ;
                             ref:hasTimeseriesId ?coolingTempSetpointTSID .
    }
    OPTIONAL {
        ?occupiedTempSetpoint a brick:Occupied_Temperature_Setpoint ;
                              brick:hasLocation ?zone ;
                              ref:hasTimeseriesId ?occupiedTempSetpointTSID .
    }
    OPTIONAL {
        ?unoccupiedTempSetpoint a brick:Unoccupied_Temperature_Setpoint ;
                                brick:hasLocation ?zone ;
                                ref:hasTimeseriesId ?unoccupiedTempSetpointTSID .
    }
    OPTIONAL {
        ?occupancySensor a brick:Occupancy_Sensor ;
                         brick:hasLocation ?zone ;
                         ref:hasTimeseriesId ?occupancySensorTSID .
    }
    OPTIONAL {
        ?occupancyCommand a brick:Occupancy_Command ;
                          brick:hasLocation ?zone ;
                          ref:hasTimeseriesId ?occupancyCommandTSID .
    }
    OPTIONAL {
        ?vav a brick:VAV ;
             brick:serves ?zone .
        OPTIONAL {
            ?damper a brick:Damper_Position_Setpoint ;
                    brick:isPointOf ?vav ;
                    ref:hasTimeseriesId ?damperTSID .
        }
        OPTIONAL {
            ?dischargeTemp a brick:Discharge_Air_Temperature_Sensor ;
                           brick:isPointOf ?vav ;
                           ref:hasTimeseriesId ?dischargeTempTSID .
        }
        OPTIONAL {
            ?reheatCommand a brick:Reheat_Command ;
                           brick:isPointOf ?vav ;
                           ref:hasTimeseriesId ?reheatCommandTSID .
        }
    }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?electricPowerSensorLabel
WHERE {
  brick:Electric_Power_Sensor rdfs:label ?electricPowerSensorLabel .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>

SELECT ?class ?type ?label
WHERE {
  {
    ?class a brick:Equipment .
    BIND("Equipment" AS ?type)
    OPTIONAL { ?class rdfs:label ?label . }
  } UNION {
    ?class a brick:Zone_Air_Temperature_Setpoint .
    BIND("Zone Air Temperature Setpoint" AS ?type)
    OPTIONAL { ?class rdfs:label ?label . }
  }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX sh: <http://www.w3.org/ns/shacl#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?deviceClass ?deviceLabel ?associatedTag ?tagLabel
WHERE {
  ?deviceClass a owl:Class ;
               a sh:NodeShape .
  OPTIONAL { ?deviceClass rdfs:label ?deviceLabel . }
  OPTIONAL {
    ?deviceClass brick:hasAssociatedTag ?associatedTag .
    OPTIONAL { ?associatedTag rdfs:label ?tagLabel . }
  }
}

PREFIX brick: <https://brickschema.org/schema/Brick#> 
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> 
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#> 
PREFIX ns1: <http://www.kgqa.com/> 
SELECT ?timeseriesId 
WHERE { 
    ?entity a brick:Power_Measurement ; 
           brick:hasTimeseriesId ?timeseriesId . 
    FILTER REGEX(STR(?entity), 'flexible_', 'i') . 
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT (SUM(?area) AS ?TotalFloorSpace)
WHERE {
  ?b a brick:Building ;
     brick:hasFloorArea ?area .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX qudtqk: <http://qudt.org/vocab/quantitykind/>
SELECT DISTINCT ?setpointClass ?label WHERE {
  ?setpointClass a owl:Class .
  { ?setpointClass rdfs:subClassOf* brick:Air_Temperature_Setpoint . }
  UNION
  { ?setpointClass rdfs:subClassOf* brick:Temperature_Setpoint .
    ?setpointClass brick:hasSubstance brick:Air .
  }
  OPTIONAL { ?setpointClass rdfs:label ?label . }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?terminal ?zone ?ahu
WHERE {
  ?terminal a brick:Underfloor_Air_Plenum .
  ?ahu a brick:Air_Handling_Unit ;
       brick:feeds ?terminal .
  OPTIONAL { ?terminal brick:feeds ?zone . }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?series
WHERE {
  ?series brick:measuredPowerOutput ?power .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ns2: <http://qudt.org/schema/qudt/>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?device ?deviceLabel ?sensor ?sensorLabel ?desired
WHERE {
  # Devices that control air temperature in zones (indicated by substance being Zone_Air)
  ?device a owl:Class ;
          rdfs:label ?deviceLabel ;
          ns2:hasQuantityKind <http://qudt.org/vocab/quantitykind/Temperature> ;
          brick:hasSubstance brick:Zone_Air .
  FILTER (CONTAINS(LCASE(?deviceLabel), "setpoint"))

  OPTIONAL { ?device brick:hasQuantity ?desired . }
  OPTIONAL {
    ?device brick:hasAssociatedTag ?tag .
    ?tag brick:isAssociatedWith ?sensor .
    OPTIONAL { ?sensor rdfs:label ?sensorLabel . }
  }
}
ORDER BY ?deviceLabel

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?prop ?label ?ALC ?MPC
WHERE {
  ?prop a brick:WaterToWaterHeatPump .
  ?prop rdfs:label ?label .
  ?prop brick:externalReference ?extRef .
  ?extRef brick:nonWritable true .
  OPTIONAL { ?extRef brick:ALCEndpoint ?ALC . }
  OPTIONAL { ?extRef brick:MPCEndpoint ?MPC . }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?pump ?pumpLabel ?endpoint
WHERE {
  ?pump a brick:WaterToWaterHeatPump ;
        brick:hasEndpoint ?endpoint .
  ?endpoint brick:accessMode "read-only" .
  OPTIONAL { ?pump rdfs:label ?pumpLabel . }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?ahu ?measurement ?measurementType ?timeseriesId
WHERE {
  ?ahu a brick:Air_Handler_Unit ;
       brick:supplies ?space ;
       brick:hasPoint ?measurement .
  ?space a brick:Space .
  ?measurement brick:hasTimeseries ?ts .
  ?ts brick:identifier ?timeseriesId .
  BIND(
    IF(EXISTS { ?measurement a brick:Supply_Air_Temperature_Measurement }
       , "Supply Air Temperature",
         IF(EXISTS { ?measurement a brick:Supply_Air_Flow_Measurement } 
            , "Supply Air Flow",
              "Flow Setpoint"
         )
    ) AS ?measurementType
  )
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?zone ?zoneLabel ?tempSensor ?tempValue ?setpoint ?setpointValue ?occupancy ?occupancyValue ?vav ?vavLabel
WHERE {
  ?zone a brick:Zone .
  ?zone rdfs:label ?zoneLabel .
  ?tempSensor a brick:Zone_Air_Temperature_Sensor .
  OPTIONAL { ?tempSensor brick:value ?tempValue . }
  OPTIONAL {
    ?setpoint a brick:Zone_Air_Temperature_Setpoint .
    OPTIONAL { ?setpoint brick:value ?setpointValue . }
  }
  OPTIONAL {
    ?occupancy a brick:Unoccupied_Zone_Air_Temperature_Setpoint .
    OPTIONAL { ?occupancy brick:value ?occupancyValue . }
  }
  OPTIONAL {
    ?vav a brick:VAV .
    ?vav rdfs:label ?vavLabel .
    # Ensuring the VAV is associated with Supply Air by requiring its membership in that class
    ?vav a brick:Supply_Air .
  }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?uft ?property ?label ?aspect ?value ?unit
WHERE {
  ?uft a brick:UFT .
  ?uft brick:hasProperty ?property .
  ?property a ?type .
  VALUES ?type { brick:Volume brick:Heat_Flow_Rate } .
  ?property brick:hasLabel ?label .
  OPTIONAL { ?property brick:hasAspect ?aspect . }
  OPTIONAL { ?property brick:hasValue ?value . }
  OPTIONAL { ?property brick:hasUnit ?unit . }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX tag: <https://brickschema.org/schema/BrickTag#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?point ?label
WHERE {
  ?point a brick:Tag ;
         rdfs:label ?label .
  FILTER(regex(?label, "^Point$", "i"))
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX dcterms: <http://purl.org/dc/terms/>

# This query aggregates descriptive metadata for each measurement point
SELECT ?terminal ?measurementType (GROUP_CONCAT(DISTINCT ?desc; separator=' | ') AS ?descriptions) (SAMPLE(?value) AS ?value) (SAMPLE(?unit) AS ?unit)
WHERE {
  ?terminal a brick:UnitaryFanTerminal ;
            brick:hasPoint ?point .
  {
    ?point a brick:Volume_Flow_Measurement .
    BIND("Volume Flow" AS ?measurementType)
  } UNION {
    ?point a brick:Heat_Flow_Measurement .
    BIND("Heat Flow" AS ?measurementType)
  }
  OPTIONAL { ?point dcterms:description ?desc . }
  OPTIONAL { ?point brick:hasValue ?value . }
  OPTIONAL { ?point brick:hasUnit ?unit . }
}
GROUP BY ?terminal ?measurementType
ORDER BY ?terminal ?measurementType

PREFIX brick: <https://brickschema.org/schema/Brick#>

SELECT ?building ?area
WHERE {
  ?building a brick:Building .
  ?building brick:floorArea ?area .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?sensor ?label
WHERE {
  ?sensor rdfs:label ?label .
  FILTER(regex(?label, "(Power|Demand|Consumption)", "i"))
  {
    ?sensor a brick:Thermal_Power_Meter .
  } UNION {
    ?sensor a brick:Heating_Demand_Sensor .
  }
}
ORDER BY ?label

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>

SELECT ?zone ?ifcGlobalID ?tsid WHERE {
  ?zone a brick:Zone ;
        ref:ifcGlobalID ?ifcGlobalID .

  ?setpoint a brick:Min_Air_Temperature_Setpoint ;
            brick:isPointOf/brick:isLocatedIn/brick:isPartOf* ?zone ;
            ref:hasExternalReference [ ref:hasTimeseriesId ?tsid ] .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?setpoint ?label
WHERE {
  ?setpoint a owl:Class ;
            rdfs:label ?label ;
            rdfs:subClassOf brick:Air_Temperature_Setpoint .
  FILTER(CONTAINS(?label, "Zone Air"))
}

PREFIX brick: <https://brickschema.org/schema/Brick#>

SELECT ?sensor ?zone
WHERE {
  {
    ?sensor a brick:Zone_Air_Temperature_Sensor .
  } UNION {
    ?sensor a brick:Average_Zone_Air_Temperature_Sensor .
  } UNION {
    ?sensor a brick:Coldest_Zone_Air_Temperature_Sensor .
  } UNION {
    ?sensor a brick:Warmest_Zone_Air_Temperature_Sensor .
  }
  OPTIONAL { ?sensor brick:hasSubstance ?zone . }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>

SELECT ?zoneName ?dataStreamID WHERE {
    ?zone a brick:Zone ;
          ref:ifcName ?zoneName ;
          brick:hasPart* ?equipment .
    ?sensor a brick:Temperature_Sensor ;
            ref:hasTimeseriesId ?dataStreamID ;
            ^brick:hasPoint ?equipment .
}

PREFIX bob: <http://data.ashrae.org/standard223/si-builder#>
PREFIX ex1: <http://data.ashrae.org/standard223/data/lbnl-example-2#>
PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?propertyLabel ?alcEndpoint ?mpcEndpoint WHERE {
  # Find non-writable external references
  ?extRef a s223:ExternalReference ;
          s223:writable "false"^^xsd:boolean .

  # Connect properties to external references and equipment
  ?property s223:hasExternalReference ?extRef ;
            s223:isPropertyOf ?equipment .

  # Filter for water-to-water heat pumps
  ?equipment a s223:WaterToWaterHeatPump .

  # Get property labels
  OPTIONAL { ?property rdfs:label ?propertyLabel }

  # Get endpoints directly from external references
  OPTIONAL { ?extRef s223:source ?alcEndpoint }
  OPTIONAL { ?extRef s223:mpc_db_name ?mpcEndpoint }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?sensor ?setpoint WHERE {
  ?sensor a brick:Sensor.
  ?setpoint a brick:Setpoint.

  ?sensor brick:isPointOf ?sensorEquipment.
  ?setpoint brick:isPointOf ?setpointEquipment.

  {
    ?setpointEquipment brick:feeds* ?sensorEquipment.
  }
  UNION
  {
    ?sensorEquipment brick:feeds* ?setpointEquipment.
  }
}
ORDER BY ?sensor ?setpoint

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?building ?areaValue WHERE {
    ?building a brick:Building ;
              brick:hasQuantity ?areaQuantity .
    ?areaQuantity a brick:Area ;
                  brick:value ?areaValue .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?sensor ?sensorLabel ?equipmentLabel
WHERE {
  ?sensor a brick:Zone_Air_Temperature_Sensor ;
          rdfs:label ?sensorLabel .

  # Assume the sensor label is of the form '...Zone Air Temp'; extract the equipment part
  BIND(REPLACE(?sensorLabel, "\\.Zone Air Temp$", "") AS ?equipmentLabel) .
}
ORDER BY ?sensor

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?zone ?vav ?point ?point_type ?ts_id ?category WHERE {
    {
        # Zone temperature control and occupancy points
        ?zone a brick:HVAC_Zone .
        ?zone brick:hasPoint ?point .
        ?point a ?point_type .
        VALUES (?superclass ?category) {
            (brick:Zone_Air_Temperature_Sensor "Zone Temperature")
            (brick:Temperature_Setpoint "Zone Setpoint")
            (brick:Occupancy_Sensor "Occupancy")
        }
        ?point_type rdfs:subClassOf* ?superclass .
        ?point ref:hasExternalReference/ref:hasTimeseriesId ?ts_id .
    }
    UNION
    {
        # VAV equipment and their control points
        ?vav a brick:Terminal_Unit ;
             brick:feeds ?zone ;
             brick:hasPoint ?point .

        ?point a ?point_type .
        VALUES (?superclass ?category) {
            (brick:Damper_Position_Setpoint "VAV Damper Control")
            (brick:Valve_Command "VAV Valve Control")
            (brick:Discharge_Air_Flow_Sensor "VAV Airflow")
            (brick:Discharge_Air_Temperature_Sensor "VAV Discharge Temp")
            (brick:Command "VAV Command")
            (brick:Status "VAV Status")
        }
        ?point_type rdfs:subClassOf* ?superclass .
        ?point ref:hasExternalReference/ref:hasTimeseriesId ?ts_id .
    }
}
ORDER BY ?zone ?vav ?category

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>

SELECT DISTINCT ?zoneName ?dataStreamId WHERE {
    ?zone a brick:Zone ;
          brick:name ?zoneName ;
          brick:hasPart ?space .

    ?sensor a brick:Occupancy_Sensor ;
            brick:hasTimeseriesId ?dataStreamId ;
            (brick:isPointOf/brick:hasLocation | brick:hasLocation) ?space .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>

SELECT DISTINCT ?zoneId ?tsId WHERE {
  ?zone a brick:Zone ;
        ref:ifcGlobalID ?zoneId ;
        brick:hasPart* ?space .

  ?space brick:isLocationOf ?equip .

  ?setpoint a brick:Max_Air_Temperature_Setpoint ;
            brick:isPointOf ?equip ;
            ref:hasExternalReference [ ref:hasTimeseriesId ?tsId ] .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ns2: <http://buildsys.org/ontologies/bldg11#>

SELECT ?sensor ?zone ?servingEquipment WHERE {
  ?sensor a brick:Zone_Air_Temperature_Sensor ;
           brick:isPartOf ?zone .

  # Find equipment serving the zone through VAV relationships
  ?vav brick:feeds ?zone ;
       brick:isPartOf ?servingEquipment .

  # Limit to AHU equipment (common parent of VAV systems)
  ?servingEquipment a brick:Air_Handling_Unit .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>

SELECT ?zone ?ifcName ?timeseriesId WHERE {
    ?zone a brick:Zone .

    # Get IFC name from zone's external reference
    OPTIONAL { ?zone ref:hasExternalReference [ ref:ifcName ?ifcName ] }

    # Find max temperature setpoints and their timeseries IDs
    ?setpoint a brick:Max_Air_Temperature_Setpoint .
    OPTIONAL { ?setpoint ref:hasExternalReference [ ref:hasTimeseriesId ?timeseriesId ] }

    # Connect setpoint to equipment
    ?equipment brick:hasPoint ?setpoint .

    # Connect equipment location to zone via spaces
    OPTIONAL {
        ?equipment brick:hasLocation ?space .
        ?space brick:isPartOf* ?zone
    }

    # Filter for valid connections
    FILTER(BOUND(?ifcName) && BOUND(?timeseriesId) && BOUND(?space))
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX s223: <http://data.ashrae.org/standard223#>

SELECT ?ahuLabel ?pointLabel ?alcEndpoint ?mpcEndpoint WHERE {
  ?ahu a brick:AHU ;
       rdfs:label ?ahuLabel .
  FILTER(CONTAINS(LCASE(?ahuLabel), "rtu"))

  ?ahu brick:hasPoint ?point .
  ?point rdfs:label ?pointLabel .

  FILTER NOT EXISTS { ?point a brick:Writable }

  OPTIONAL { ?point s223:hasALCEndpoint ?alcEndpoint }
  OPTIONAL { ?point s223:hasMPCEndpoint ?mpcEndpoint }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>

SELECT ?device ?measurement ?target WHERE {
  ?measurement a brick:Zone_Air_Temperature_Sensor ;
               brick:isPointOf ?device .
  ?target a brick:Zone_Air_Temperature_Setpoint ;
          brick:isPointOf ?device .
  ?device a ?controller .
  FILTER (?controller IN (brick:Thermostat, brick:VAV, brick:TerminalUnit))
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>

SELECT ?zoneName ?tsId WHERE {
    ?space a brick:Space ;
           brick:isPartOf ?zone .
    ?zone ref:hasExternalReference [ ref:ifcName ?zoneName ] .
    ?sensor a brick:Occupancy_Sensor ;
            brick:isLocatedIn ?space ;
            ref:hasExternalReference [ ref:hasTimeseriesId ?tsId ] .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ns2: <http://buildsys.org/ontologies/bldg11#>

SELECT ?room ?sensor ?setpoint ?ahu ?vav WHERE {
  ?ahu a brick:Air_Handling_Unit ;
       brick:feeds ?vav .

  ?vav a brick:VAV ;
       brick:feeds ?room .

  ?sensor a brick:Zone_Air_Temperature_Sensor ;
          brick:isPointOf ?vav .

  ?setpoint a brick:Zone_Temperature_Setpoint ;
            brick:isPointOf ?vav .
}

PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX bob: <http://data.ashrae.org/standard223/si-builder#>

SELECT ?heatPump ?property ?propertyLabel ?alcEndpoint ?mpcEndpoint WHERE {
  ?heatPump a s223:Equipment ;
    s223:hasProperty ?property ;
    s223:hasExternalReference ?extRef .

  # Check for hot and chilled water connections using UNION patterns
  {
    { ?heatPump s223:hasConnectionPoint [ s223:hasMedium s223:Water-HotWater ] }
    UNION
    { ?heatPump s223:hasConnectionPoint [ s223:hasMedium bob:HotWater ] }
  }
  {
    { ?heatPump s223:hasConnectionPoint [ s223:hasMedium s223:Water-ChilledWater ] }
    UNION
    { ?heatPump s223:hasConnectionPoint [ s223:hasMedium bob:ChilledWater ] }
  }

  ?property rdfs:label ?propertyLabel .

  # Get non-writable external reference details from heat pump
  ?extRef a s223:ExternalReference ;
    s223:writable "False" ;
    s223:source ?alcEndpoint ;
    s223:mpc_db_name ?mpcEndpoint .
}

PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX ref: <https://brickschema.org/schema/Brick/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ex1: <http://data.ashrae.org/standard223/data/lbnl-example-2#>

SELECT ?propertyLabel ?endpoint ?mpcName WHERE {
  # Find water-to-water heat pump via connection mediums
  ?heatPump a s223:Equipment ;
            s223:hasConnectionPoint/s223:hasMedium s223:Water-HotWater ;
            s223:hasConnectionPoint/s223:hasMedium s223:Fluid-Water ;
            s223:hasProperty ?property .

  # Match observable properties with external references
  ?property a s223:QuantifiableObservableProperty ;
            ref:writable "False" ;
            ref:endpoint ?endpoint ;
            ex1:mpc_db_name ?mpcName ;
            rdfs:label ?propertyLabel .

  # Verify property-source relationships exist
  FILTER EXISTS { ?property ref:endpoint [] }
  FILTER EXISTS { ?property ex1:mpc_db_name [] }
}

PREFIX bob: <http://data.ashrae.org/standard223/si-builder#>
PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX ref: <https://brickschema.org/schema/Brick/>

SELECT DISTINCT ?ahu ?zone WHERE {
  ?ahu a ref:AHU ;
       s223:hasConnectionPoint ?ahuOutlet .
  ?ahuOutlet a bob:AirConnectionPoint .

  ?terminal a ref:TerminalUnit ;
            s223:hasConnectionPoint ?terminalInlet, ?terminalOutlet .
  ?terminalInlet a bob:AirConnectionPoint ;
                 s223:connectedTo ?ahuOutlet .

  ?zone a ref:Zone ;
        s223:hasConnectionPoint ?zoneInlet .
  ?zoneInlet a bob:AirConnectionPoint ;
             s223:connectedTo ?terminalOutlet .

  ?subsystem a s223:UnderfloorAirDistributionSystem ;
             s223:contains ?terminal .
}

PREFIX ref: <https://brickschema.org/schema/Brick/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX s223: <http://data.ashrae.org/standard223#>

SELECT DISTINCT ?propertyName ?alcEndpoint ?mpcEndpoint
WHERE {
    ?rtu a ref:RTU .
    ?rtu ref:hasPoint ?point .

    FILTER (EXISTS { ?point ref:source ?s } || EXISTS { ?point ref:mpc_db_name ?m })

    OPTIONAL { ?point rdfs:label ?label . }
    BIND(COALESCE(?label, REPLACE(STR(?point), ".*[/#]", "")) AS ?propertyName)

    OPTIONAL { ?point ref:source ?alcEndpoint . }
    OPTIONAL { ?point ref:mpc_db_name ?mpcEndpoint . }
}

PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT DISTINCT ?extRef ?propertyLabel ?alcEndpointAddress ?mpcEndpointAddress
WHERE {
    ?extRef a s223:ExternalReference .

    # Find a property associated with this external reference
    ?extRef s223:hasProperty ?waterHeatPumpProperty .

    # Ensure this property is non-writable (using ASHRAE 223p predicate and boolean literal)
    ?waterHeatPumpProperty s223:isWritable "false"^^xsd:boolean .

    # Link property to a Point or Parameter, which is part of a Water-to-Water Heat Pump component, and has a water medium
    {
        ?waterHeatPumpProperty s223:isPropertyOf ?point .
        ?point a s223:Point .
        ?point s223:isPointOf ?component .
        ?component a s223:WaterToWaterHeatPump .
        {
            ?point s223:hasMedium s223:Water-HotWater .
        }
        UNION
        {
            ?point s223:hasMedium s223:Fluid-Water .
        }
    }
    UNION
    {
        ?waterHeatPumpProperty s223:isPropertyOf ?parameter .
        ?parameter a s223:Parameter .
        ?parameter s223:isParameterOf ?component .
        ?component a s223:WaterToWaterHeatPump .
        {
            ?parameter s223:hasMedium s223:Water-HotWater .
        }
        UNION
        {
            ?parameter s223:hasMedium s223:Fluid-Water .
        }
    }

    # Get the label of the property
    OPTIONAL { ?waterHeatPumpProperty rdfs:label ?propertyLabel . }

    # Get ALC endpoint from the ExternalReference (using ASHRAE 223p structure)
    OPTIONAL {
        ?extRef s223:hasEndpoint ?alcEndpointNode .
        ?alcEndpointNode s223:hasEndpointType s223:ALCEndpoint .
        ?alcEndpointNode s223:hasEndpointAddress ?alcEndpointAddress .
    }

    # Get MPC endpoint from the ExternalReference (using ASHRAE 223p structure)
    OPTIONAL {
        ?extRef s223:hasEndpoint ?mpcEndpointNode .
        ?mpcEndpointNode s223:hasEndpointType s223:MPCEndpoint .
        ?mpcEndpointNode s223:hasEndpointAddress ?mpcEndpointAddress .
    }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>

SELECT DISTINCT ?timeseriesId
WHERE {
    ?point ref:hasExternalReference ?ref .
    ?ref ref:hasTimeseriesId ?timeseriesId .

    ?point a brick:Power_Sensor .

    { ?ref ref:onTable "baseline_tempData_dataset" . }
    UNION
    { ?ref ref:storedAt "data.db" . }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
PREFIX saref: <https://saref.etsi.org/core#>
PREFIX s4bldg: <https://saref.etsi.org/saref4bldg#>

SELECT DISTINCT ?zoneName ?timeseriesId
WHERE {
    ?zone a brick:Zone .
    OPTIONAL { ?zone ref:ifcName ?ifcName . }
    BIND(COALESCE(?ifcName, REPLACE(STR(?zone), ".*#", "")) AS ?zoneName) .

    OPTIONAL {
        ?sensor a brick:Occupancy_Sensor .

        # Define how the sensor "monitors" the zone using UNION for different patterns
        {
            ?sensor brick:monitors ?zone .
        }
        UNION
        {
            ?zone brick:hasPart ?space .
            ?sensor brick:monitors ?space .
        }
        UNION
        {
            # Original query's path for indirect association
            ?zone brick:hasPart ?space_indirect .
            ?equipment brick:hasLocation ?space_indirect .
            ?equipment brick:hasPoint ?sensor .
        }

        # Find timeseriesId for the found sensor
        OPTIONAL {
            ?sensor ref:hasExternalReference ?extRef .
            ?extRef ref:hasTimeseriesId ?timeseriesId .
        }
        OPTIONAL {
            ?sensor ref:hasTimeseriesId ?timeseriesId .
        }
    }
}
ORDER BY ?zoneName

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
PREFIX saref: <https://saref.etsi.org/core#>
PREFIX om: <http://openmetrics.eu/openmetrics#>

SELECT ?zone ?ifcGlobalID ?timeseriesID
WHERE {
    ?zone a brick:Zone .

    # Try to find IFC Global ID for the zone
    OPTIONAL { ?zone ref:ifcGlobalID ?ifcGlobalID . }

    # Try to find an occupancy sensor associated with the zone
    OPTIONAL {
        # Path 1: Equipment in Space in Zone, Sensor is a point of Equipment
        {
            ?zone brick:hasPart ?space .
            ?equipment brick:hasLocation ?space .
            { ?equipment brick:hasPoint ?sensor . }
            UNION
            { ?equipment saref:consistOf ?sensor . }
        }
        UNION
        # Path 2: Sensor directly in Space in Zone
        {
            ?zone brick:hasPart ?space .
            ?sensor brick:hasLocation ?space .
        }

        # Define what an occupancy sensor is
        { ?sensor a brick:Occupancy_Sensor . }
        UNION
        { ?sensor a saref:Sensor . ?sensor saref:observes om:OccProperty . }

        # Try to find Timeseries ID for the sensor
        OPTIONAL { ?sensor ref:hasTimeseriesId ?timeseriesID . }
    }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ns2: <http://buildsys.org/ontologies/bldg11#>

SELECT ?equipment ?point WHERE {
  ?equipment brick:hasPoint ?point .
  ?point a brick:Zone_Air_Temperature_Setpoint .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
PREFIX saref: <https://saref.etsi.org/core#>
PREFIX s4bldg: <https://saref.etsi.org/saref4bldg#>

SELECT DISTINCT ?timeseriesId ?zoneName
WHERE {
    ?minTempSetpoint a brick:Min_Air_Temperature_Setpoint .
    ?minTempSetpoint ref:hasExternalReference ?externalRef .
    ?externalRef ref:hasTimeseriesId ?timeseriesId .

    ?minTempSetpoint brick:isPointOf ?equipment .

    {
        # Case 1: Equipment is directly located in a Zone
        ?equipment brick:hasLocation ?zone .
        ?zone a brick:Zone .
    }
    UNION
    {
        # Case 2: Equipment is located in a Space, which is part of a Zone
        ?equipment brick:hasLocation ?space .
        { ?space a brick:Space } UNION { ?space a s4bldg:BuildingSpace } .
        ?zone brick:hasPart ?space .
        ?zone a brick:Zone .
    }

    # Attempt to find the zone name, if available
    OPTIONAL { ?zone ref:ifcName ?zoneName . }
    OPTIONAL {
        ?zone ref:hasExternalReference ?zoneExternalRef .
        ?zoneExternalRef ref:ifcName ?zoneName .
    }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
SELECT DISTINCT ?equipment WHERE {
  ?equipment a brick:Equipment .
  ?equipment brick:hasPoint ?point .
  ?point a brick:Supply_Air_Temperature_Sensor .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?building (COALESCE(?directAreaValue, ?summedPartArea) AS ?totalArea) (COALESCE(?directUnit, ?partUnit) AS ?unit) WHERE {
  ?building a brick:Building .

  OPTIONAL {
    ?building brick:hasArea ?directAreaInstance .
    ?directAreaInstance brick:hasQuantity ?directQuantityValue .
    ?directQuantityValue qudt:numericValue ?directAreaValue .
    ?directQuantityValue qudt:unit ?directUnit .
  }

  OPTIONAL {
    SELECT ?building_sub (SUM(?pAreaValue) AS ?summedPartArea) ?pUnit WHERE {
      ?building_sub brick:hasPart* ?space .
      ?space a/rdfs:subClassOf* brick:Location .
      ?space brick:hasArea ?partAreaInstance .
      ?partAreaInstance brick:hasQuantity ?partQuantityValue .
      ?partQuantityValue qudt:numericValue ?pAreaValue .
      ?partQuantityValue qudt:unit ?pUnit .
    }
    GROUP BY ?building_sub ?pUnit
  }

  BIND(?building AS ?building_sub)
  FILTER(BOUND(?totalArea))
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
PREFIX saref: <https://saref.etsi.org/core#>
PREFIX s4bldg: <https://saref.etsi.org/saref4bldg#>
PREFIX om: <http://openmetrics.eu/openmetrics#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?zoneName ?dataStreamId
WHERE {
    ?zone a brick:Zone .

    # Try to get IFC name, fallback to rdfs:label for robustness
    OPTIONAL { ?zone ref:ifcName ?ifcName . }
    OPTIONAL { ?zone rdfs:label ?rdfsLabel . }
    BIND(COALESCE(?ifcName, ?rdfsLabel) AS ?zoneName) .
    FILTER(BOUND(?zoneName)) # Ensure we get some name for the zone

    # Define how a sensor can be associated with a space (and thus a zone)
    {
        # Path 1: Sensor is a point of equipment located in the space
        ?zone brick:hasPart ?space .
        ?equipment brick:hasLocation ?space .
        ?equipment brick:hasPoint ?sensor .
    }
    UNION
    {
        # Path 2: Sensor is directly located in the space
        ?zone brick:hasPart ?space .
        ?sensor brick:hasLocation ?space .
    }

    # Identify Temperature Sensors (Brick or ASHRAE 223p)
    {
        ?sensor a brick:Temperature_Sensor .
    }
    UNION
    {
        ?sensor a saref:Sensor .
        ?sensor saref:observes om:TempProperty .
    }

    # Get the data stream ID, make it optional to see if sensors exist without it
    OPTIONAL { ?sensor ref:hasTimeseriesId ?dataStreamId_raw . }
    BIND(COALESCE(?dataStreamId_raw, "N/A") AS ?dataStreamId) # Provide 'N/A' if no ID is found
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?equipment 
  (GROUP_CONCAT(DISTINCT ?sensor; separator=", ") AS ?sensors)
  (GROUP_CONCAT(DISTINCT ?setpoint; separator=", ") AS ?setpoints)
WHERE {
  {
    ?equipment brick:hasPoint ?sensor .
    ?sensor a/rdfs:subClassOf* brick:Sensor .
  } UNION {
    ?equipment brick:hasPoint ?setpoint .
    ?setpoint a/rdfs:subClassOf* brick:Setpoint .
  }
}
GROUP BY ?equipment

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX om: <http://openmetrics.eu/openmetrics#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
PREFIX saref: <https://saref.etsi.org/core#>

SELECT DISTINCT ?zoneName ?timeseriesId
WHERE {
    ?zone a brick:Zone .
    ?zone ref:ifcName ?zoneName .
    ?zone brick:hasPart ?space .

    {
        ?equipment brick:hasLocation ?space .
        ?equipment brick:hasPoint ?sensor .
    }
    UNION
    {
        ?sensor brick:hasLocation ?space .
    }

    {
        ?sensor a brick:Temperature_Sensor .
    } UNION {
        ?sensor a brick:Sensor .
        ?sensor brick:measures brick:Temperature_Property .
    }

    ?sensor ref:hasExternalReference ?extRef .
    ?extRef ref:hasTimeseriesId ?timeseriesId .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?ahu ?controlPoint WHERE {
    ?ahu a brick:Air_Handling_Unit .

    # Find associated heating/cooling coils
    ?ahu brick:hasPart+ ?coil .
    ?coil a ?coilType .
    VALUES ?coilType { brick:Heating_Coil brick:Cooling_Coil }

    # Get control points from coils
    ?coil brick:hasPoint ?controlPoint .

    # Filter for relevant setpoint types
    {
        ?controlPoint a/rdfs:subClassOf* brick:Discharge_Air_Temperature_Setpoint
    } UNION {
        ?controlPoint a/rdfs:subClassOf* brick:Heating_Command
    } UNION {
        ?controlPoint a/rdfs:subClassOf* brick:Cooling_Command
    }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
PREFIX saref: <https://saref.etsi.org/core#>

SELECT DISTINCT ?zone ?timeseriesId
WHERE {
    ?zone a brick:Zone .
    ?setpoint a brick:Max_Air_Temperature_Setpoint .
    ?setpoint ref:hasTimeseriesId ?timeseriesId .

    { # Option 1: Setpoint on equipment located in a space that is part of the zone
        ?zone brick:hasPart ?space .
        ?equipment brick:hasLocation ?space .
        { ?equipment brick:hasPoint ?setpoint . }
        UNION
        { ?equipment saref:consistOf ?setpoint . }
    }
    UNION
    { # Option 2: Setpoint on equipment that serves the zone
        ?equipment brick:serves ?zone .
        { ?equipment brick:hasPoint ?setpoint . }
        UNION
        { ?equipment saref:consistOf ?setpoint . }
    }
    UNION
    { # Option 3: Setpoint directly on the zone
        ?zone brick:hasPoint ?setpoint .
    }
}

PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX quantitykind: <http://qudt.org/vocab/quantitykind/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX btag: <https://brickschema.org/schema/BrickTag#>

SELECT DISTINCT ?fan ?point ?pointType ?quantityKind ?label
WHERE {
  # Identify Fan equipment, allowing for both s223:Fan and brick:Fan
  {
    ?fan a s223:Fan .
  }
  UNION
  {
    ?fan a brick:Fan .
  }

  # Link to data points. Brick Points are commonly used for observable data.
  # We look for points directly associated with the fan.
  ?fan brick:hasPoint ?point .

  # Ensure ?point is a Brick Point
  ?point a brick:Point .

  # Filter for Volume Flow or Heat Flow related points using Brick properties
  {
    # Option 1: By Brick Point Type (e.g., Air_Flow_Sensor, Heat_Flow_Sensor)
    ?point a ?pointType .
    FILTER(?pointType IN (
      brick:Air_Flow_Sensor, brick:Air_Flow_Meter, brick:Volume_Flow_Sensor, brick:Volume_Flow_Meter,
      brick:Heat_Flow_Sensor, brick:Heat_Flow_Meter, brick:Enthalpy_Sensor
    ))
    BIND(STR(?pointType) AS ?quantityKind) # Use the type URI as a proxy for quantityKind
    OPTIONAL { ?point rdfs:label ?label . }
  }
  UNION
  {
    # Option 2: By Brick Quantity (e.g., Air_Flow_Rate, Heat_Flow_Rate)
    ?point brick:hasQuantity ?quantity .
    FILTER(?quantity IN (
      brick:Air_Flow_Rate, brick:Volume_Flow_Rate, brick:Heat_Flow_Rate, brick:Enthalpy
    ))
    BIND(STR(?quantity) AS ?quantityKind) # Use the quantity URI as quantityKind
    BIND(?point AS ?pointType) # Use the point URI as a proxy for pointType
    OPTIONAL { ?point rdfs:label ?label . }
  }
  UNION
  {
    # Option 3: By QUDT QuantityKind (less common for Brick points, but possible)
    ?point qudt:hasQuantityKind ?qk .
    FILTER(?qk IN (quantitykind:VolumeFlowRate, quantitykind:HeatFlowRate))
    BIND(STR(?qk) AS ?quantityKind)
    BIND(?point AS ?pointType)
    OPTIONAL { ?point rdfs:label ?label . }
  }
  UNION
  {
    # Option 4: By Brick Tag (e.g., btag:Air_Flow, btag:Heat_Flow)
    ?point brick:hasTag ?tag .
    FILTER(?tag IN (btag:Air_Flow, btag:Heat_Flow))
    BIND(STR(?tag) AS ?quantityKind) # Use the tag URI as quantityKind
    BIND(?point AS ?pointType)
    OPTIONAL { ?point rdfs:label ?label . }
  }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?device ?measurementInstrument ?controlValue
WHERE {
    ?device a/rdfs:subClassOf* brick:Equipment .

    OPTIONAL {
        ?device brick:hasPoint ?measurementInstrument .
        ?measurementInstrument a/rdfs:subClassOf* brick:Sensor .
    }

    OPTIONAL {
        ?device brick:hasPoint ?controlValue .
        ?controlValue a ?controlValueType .
        {
            ?controlValueType rdfs:subClassOf* brick:Command .
        }
        UNION
        {
            ?controlValueType rdfs:subClassOf* brick:Setpoint .
        }
    }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ns2: <http://buildsys.org/ontologies/bldg11#>

SELECT ?meter ?sensor WHERE {
  { ?meter a brick:Electric_Meter }
  UNION
  { ?sensor a brick:Outside_Air_Temperature_Sensor }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>

SELECT ?electricity_meter ?weather_sensor ?meter_timeseries_id ?weather_timeseries_id WHERE {
  ?electricity_meter rdf:type brick:Electric_Meter .
  OPTIONAL { ?electricity_meter ref:hasTimeseriesId ?meter_timeseries_id . }

  ?weather_sensor rdf:type brick:Outside_Air_Enthalpy_Sensor .
  OPTIONAL { ?weather_sensor ref:hasTimeseriesId ?weather_timeseries_id . }
}

PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX ref: <https://brickschema.org/schema/Brick/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?rtu ?rtuLabel ?property ?propertyLabel ?endpoint ?endpointLabel
WHERE {
  # Identify RTU units using a dedicated RTU class. Adjust the class below if your implementation uses a different one (e.g., s223:RTU).
  ?rtu a ref:RTU .
  OPTIONAL { ?rtu rdfs:label ?rtuLabel. }

  # Retrieve properties associated with the RTU unit
  ?rtu s223:hasProperty ?property .

  # Ensure the property is read-only by requiring it be an ObservableProperty but not an ActuatableProperty
  ?property a s223:ObservableProperty .
  FILTER NOT EXISTS { ?property a s223:QuantifiableActuatableProperty } .
  OPTIONAL { ?property rdfs:label ?propertyLabel. }

  # Retrieve the control endpoint from the property via known connectivity predicates
  {
    ?property s223:cnx ?endpoint .
  } UNION {
    ?property s223:connectsAt ?endpoint .
  } UNION {
    ?property s223:connectsThrough ?endpoint .
  }

  # Ensure the endpoint is explicitly typed as a ControlEndpoint
  ?endpoint a s223:ControlEndpoint .
  OPTIONAL { ?endpoint rdfs:label ?endpointLabel. }
}

PREFIX bldg1: <urn:bldg/>
PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>

# This query aggregates the floor area for all facilities, where a facility is identified
# as either a brick:Building or brick:Facility. Floor area may be represented directly via the property
# brick:hasFloorArea or indirectly via a Floor_Area_Sensor that has a measurement with a value.

SELECT (SUM(?area) AS ?TotalFloorSpace)
WHERE {
  {
    # Option 1: Direct floor area on the facility
    {
      { ?facility a brick:Building . } UNION { ?facility a brick:Facility . }
      ?facility brick:hasFloorArea ?area .
    }
    UNION
    # Option 2: Floor area provided by a sensor's measurement
    {
      { ?facility a brick:Building . } UNION { ?facility a brick:Facility . }
      ?facility brick:hasPoint ?point .
      ?point a brick:Floor_Area_Sensor .
      ?point brick:hasMeasurement ?measurement .
      ?measurement brick:hasValue ?area .
    }
  }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref:   <https://brickschema.org/schema/Brick/ref#>

SELECT ?zoneIFCName ?timeseriesId
WHERE {
  ?zone a brick:Zone ;
        brick:hasPart ?space ;
        ref:hasExternalReference ?zoneExt .
  ?zoneExt ref:ifcName ?zoneIFCName .

  ?space brick:isLocationOf ?equipment .
  ?equipment brick:hasPoint ?sensor .
  ?sensor a brick:Occupancy_Sensor ;
          ref:hasExternalReference ?sensorExt .
  ?sensorExt ref:hasTimeseriesId ?timeseriesId .
}

PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ref: <https://brickschema.org/schema/Brick/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?heatPump ?propertyLabel ?ALC ?MPC
WHERE {
  # Identify water-to-water heat pumps either by a direct type or by having both water media
  {
    ?heatPump a s223:WaterToWaterHeatPump .
  } UNION {
    ?heatPump s223:hasMedium s223:Water-HotWater .
    ?heatPump s223:hasMedium s223:Fluid-Water .
  }

  # Retrieve related properties for each heat pump
  ?heatPump s223:hasProperty ?p .
  OPTIONAL { ?p rdfs:label ?propertyLabel . }

  # For properties that are quantifiable and non-writable, retrieve ALC and MPC endpoint references
  OPTIONAL {
    ?p a ?qType .
    FILTER(?qType = s223:QuantifiableProperty || ?qType = s223:QuantifiableObservableProperty || ?qType = s223:QuantifiableActuatableProperty)
    ?p ref:writable ?writable .
    FILTER(xsd:boolean(?writable) = false)
    ?p ref:source ?ALC .
    ?p ref:mpc_db_name ?MPC .
  }
}
ORDER BY ?heatPump ?propertyLabel

PREFIX bldg1: <urn:bldg/>
PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>

SELECT DISTINCT ?tsid WHERE {
  {
    # Electrical power measurement: follow the explicit relationship from an equipment point
    # Here the chiller has a measurement point (its real power measurement) that carries an external reference.
    bldg1:chiller brick:hasPoint ?elecPoint .
    ?elecPoint ref:hasExternalReference ?extRef .
    ?extRef ref:hasTimeseriesId ?tsid .
    # Optionally, if available, we could verify that the point acts as an electrical measurement;
    # however, the explicit link via chiller assures us that this data stream identifier pertains to electrical power.
  } UNION {
    # Heat power measurements: explicitly follow the external reference on the heat pump measurement points
    # In the absence of an explicit relationship from the heat pump to its measurement points, we
    # list the two known measurement points that provide heat power data.
    VALUES ?heatPoint { bldg1:heaPum_reaPHeaPum_y bldg1:heaPum_reaPPumDis_y } .
    ?heatPoint ref:hasExternalReference ?extRef2 .
    ?extRef2 ref:hasTimeseriesId ?tsid .
  }
}

PREFIX ref: <https://brickschema.org/schema/Brick/>
PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?uftLabel ?zoneLabel ?ahuLabel
WHERE {
  # Identify the terminal unit (UFT) using the proper Brick type
  ?uft a ref:TerminalUnit ;
       rdfs:label ?uftLabel ;
       s223:cnx ?uftJunction .

  # The terminal unit is connected to a junction (using the Brick class for connection points)
  ?uftJunction a ref:AirConnectionPoint ;
               s223:cnx ?domainSpace .

  # The domain space (modeled here with an ASHRAE 223p class) must explicitly appear and contain a zone
  ?domainSpace a s223:DomainSpace ;
               s223:contains ?zone .

  # The zone is identified using the proper Brick type
  ?zone a ref:Zone ;
        rdfs:label ?zoneLabel .

  # The supplying AHU is identified by its Brick type and joins the domain space via its own junction
  ?ahu a ref:AHU ;
       rdfs:label ?ahuLabel ;
       s223:cnx ?ahuJunction .
  ?ahuJunction a ref:AirConnectionPoint ;
               s223:cnx ?domainSpace .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX qudt:  <http://qudt.org/schema/qudt/>
PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?building ?areaValue ?areaUnit WHERE {
  ?building a brick:Building ;
            ?p       ?areaMeasure .
  ?p rdfs:subPropertyOf* brick:hasArea .
  ?areaMeasure qudt:numericalValue ?areaValue ;
               qudt:unit           ?areaUnit .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref:   <https://brickschema.org/schema/Brick/ref#>

SELECT DISTINCT ?zone ?ifcGlobalId ?timeseriesId WHERE {
  # 1. Find each Zone and its IFC GUID
  ?zone a brick:Zone ;
        ref:hasExternalReference ?zExt ;
        brick:hasLocation        ?space .
  ?zExt ref:ifcGlobalId ?ifcGlobalId .

  # 2. Traverse from the Space to its Temperature_Setpoint via one or more hops
  ?space brick:hasPoint+ ?setpoint .
  ?setpoint a brick:Temperature_Setpoint .

  # 3. Get the Timeseries ID from the Timeseries link or the point’s ExternalReference
  OPTIONAL {
    ?setpoint brick:hasTimeseries ?ts .
    ?ts      ref:hasTimeseriesId ?timeseriesId .
  }
  OPTIONAL {
    ?setpoint ref:hasExternalReference ?pExt .
    ?pExt    ref:hasTimeseriesId     ?timeseriesId .
  }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX qudt:  <http://qudt.org/schema/qudt/>
PREFIX qk:    <http://qudt.org/vocab/quantitykind/>

SELECT DISTINCT ?building ?areaValue ?areaUnit WHERE {
  ?building a brick:Building ;
            brick:hasQuantity ?qty .
  ?qty qudt:quantityKind qk:Area ;
       qudt:value         ?areaValue ;
       qudt:unit          ?areaUnit .
}

PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?externalRef ?propertyLabel ?alcEndpoint ?mpcEndpoint
WHERE {
  ?externalRef a s223:ExternalReference ;
               s223:writable      false ;
               s223:referencesProperty ?prop .
  OPTIONAL { ?externalRef s223:alcEndpoint  ?alcEndpoint }
  OPTIONAL { ?externalRef s223:mpcEndpoint ?mpcEndpoint }

  ?prop rdfs:label     ?propertyLabel ;
        s223:propertyOf ?hp .
  ?hp  a s223:WaterToWaterHeatPump .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ns2: <http://buildsys.org/ontologies/bldg11#>

SELECT ?sensor ?equipment
WHERE {
  ?sensor a brick:Zone_Air_Temperature_Sensor .
  OPTIONAL { ?equipment brick:hasPoint ?sensor . }
}
ORDER BY ?sensor

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref:   <https://brickschema.org/schema/Brick/ref#>

SELECT DISTINCT ?type ?sensor ?xref ?seriesID ?storedAt ?onTableName WHERE {
  {
    # electricity consumption (energy)
    VALUES ?class { brick:Electric_Energy_Sensor brick:Electric_Meter brick:Electric_Energy_Meter }
    ?sensor a ?class ;
            (ref:hasExternalReference|ref:hasTimeseries) ?xref .
    BIND("electric_energy" AS ?type)
  }
  UNION
  {
    # heating power
    ?sensor a brick:Heating_Power_Sensor ;
            (ref:hasExternalReference|ref:hasTimeseries) ?xref .
    BIND("heating_power" AS ?type)
  }
  # retrieve timeseries metadata
  OPTIONAL { ?xref ref:hasTimeseriesID  ?seriesID   }
  OPTIONAL { ?xref ref:storedAt         ?storedAt   }
  OPTIONAL { ?xref ref:onTableName      ?onTableName }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX tag: <https://brickschema.org/schema/BrickTag#>

SELECT DISTINCT ?point
WHERE {
  { ?s brick:hasPoint ?point . }
  UNION
  { ?point brick:hasAssociatedTag tag:Point . }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?equipment ?equipmentLabel ?setpoint ?setpointLabel
WHERE {
  # find all zone air temperature setpoints
  ?setpoint a brick:Zone_Air_Temperature_Setpoint .
  # find the equipment that has each setpoint
  ?equipment brick:hasPoint ?setpoint .

  # label for equipment, with URI fragment fallback
  OPTIONAL { ?equipment rdfs:label ?_equipmentLabel }
  BIND(
    COALESCE(
      ?_equipmentLabel,
      REPLACE(
        STRAFTER(STR(?equipment), "#"),
        "_", " "
      )
    ) AS ?equipmentLabel
  )

  # label for setpoint, with URI fragment fallback
  OPTIONAL { ?setpoint rdfs:label ?_setpointLabel }
  BIND(
    COALESCE(
      ?_setpointLabel,
      REPLACE(
        STRAFTER(STR(?setpoint), "#"),
        "_", " "
      )
    ) AS ?setpointLabel
  )
}
ORDER BY ?equipmentLabel ?setpointLabel

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX s223:  <http://data.ashrae.org/standard223#>
PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?propertyName ?alcEndpoint ?mpcEndpoint WHERE {
  # Match all rooftop units (RTUs)
  ?ahu a brick:Rooftop_Unit .

  # Get each point on the RTU
  ?ahu brick:hasPoint ?pt .

  # Use the point's label as its property name
  ?pt rdfs:label ?propertyName .

  # Optional ALC endpoint via an external reference of type ALC_Reference
  OPTIONAL {
    ?pt brick:hasExternalReference ?xrefA .
    ?xrefA a s223:ALC_Reference ;
           s223:endpoint        ?alcEndpoint .
  }

  # Optional MPC endpoint via an external reference of type MPC_Reference
  OPTIONAL {
    ?pt brick:hasExternalReference ?xrefM .
    ?xrefM a s223:MPC_Reference ;
           s223:endpoint        ?mpcEndpoint .
  }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref:   <https://brickschema.org/schema/Brick/ref#>

SELECT DISTINCT ?sensor ?timeseriesId WHERE {
  {
    # dedicated Electric Power Sensor subclass
    ?sensor a brick:Electric_Power_Sensor .
  }
  UNION
  {
    # generic sensor measuring electric power
    ?sensor a brick:Sensor ;
            brick:measures brick:Electric_Power .
  }

  # link to an external/timeseries reference node
  ?sensor ?extProp ?refNode .
  VALUES ?extProp { ref:hasExternalReference ref:hasExtReference ref:hasReferenceEntry }

  # allow either ExternalReference or TimeseriesReference typing
  ?refNode a ?refType .
  VALUES ?refType { ref:ExternalReference ref:TimeseriesReference }

  # restrict to entries in the baseline table
  ?refNode ref:onTable "baseline_tempData_dataset" .

  # require a timeseries identifier
  ?refNode ref:hasTimeseriesId ?timeseriesId .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref:   <https://brickschema.org/schema/Brick/ref#>

SELECT DISTINCT ?zoneIfcName ?tsid WHERE {
  # zone with IFC name
  ?zone a brick:Zone ;
        brick:hasPart          ?space ;
        ref:hasExternalReference ?zoneRef .
  ?zoneRef a ref:ExternalReference ;
           ref:namespace        "ifc" ;
           ref:externalId       ?zoneIfcName .

  # only real spaces
  ?space a brick:Space .

  # find occupancy sensors in that space (direct or via equipment)
  {
    ?sensor a brick:Occupancy_Sensor ;
            brick:hasLocation    ?space .
  }
  UNION
  {
    ?sensor a brick:Occupancy_Sensor ;
            brick:isPointOf      ?equip .
    ?equip a brick:Equipment ;
           brick:hasLocation    ?space .
  }

  # get the sensor's timeseries
  ?sensor brick:hasTimeseries ?ts .
  ?ts a brick:Timeseries ;
      brick:hasTimeseriesId    ?tsid .
}
ORDER BY ?zoneIfcName ?tsid

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?equipment ?equipmentLabel ?sensor ?sensorLabel ?setpoint ?setpointLabel WHERE {
  # Find equipment that has both a zone air temperature sensor and a zone air temperature setpoint
  ?equipment brick:hasPoint ?sensor ;
             brick:hasPoint ?setpoint .

  # Restrict the points by Brick classes
  ?sensor    a brick:Zone_Air_Temperature_Sensor .
  ?setpoint  a brick:Zone_Air_Temperature_Setpoint .

  # Optional labels for readability
  OPTIONAL { ?equipment  rdfs:label ?equipmentLabel  }
  OPTIONAL { ?sensor     rdfs:label ?sensorLabel     }
  OPTIONAL { ?setpoint   rdfs:label ?setpointLabel   }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX tag:   <https://brickschema.org/schema/BrickTag#>
PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?system ?systemLabel ?component ?componentLabel ?sensor ?sensorLabel
WHERE {
  # Identify supply‐air temperature sensors, either strict class or generic temp sensor with a Supply tag
  { ?sensor a brick:Supply_Air_Temperature_Sensor. }
  UNION
  { ?sensor a brick:Temperature_Sensor; brick:hasTag tag:Supply. }
  OPTIONAL { ?sensor rdfs:label ?sensorLabel. }

  # Find the component on which the sensor is mounted (either direction)
  { ?component brick:hasPoint  ?sensor. }
  UNION
  { ?sensor   brick:isPointOf ?component. }

  # Restrict to plausible supply‐air locations: duct, coil, fan, or VAV box
  VALUES ?ctype { brick:Supply_Air_Duct brick:Cooling_Coil brick:Heating_Coil brick:Fan brick:Variable_Air_Volume_Box }
  ?component a/rdfs:subClassOf* ?ctype.
  OPTIONAL { ?component rdfs:label ?componentLabel. }

  # Link the component up to its parent system (AHU or VAV system)
  ?system brick:hasPart+ ?component.
  VALUES ?stype { brick:Air_Handling_Unit brick:Variable_Air_Volume_System }
  ?system a/rdfs:subClassOf* ?stype.
  OPTIONAL { ?system rdfs:label ?systemLabel. }
}
ORDER BY ?systemLabel ?componentLabel ?sensorLabel

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>

# This query explicitly retrieves labels and uses a two‐step approach:
# 1. Identify temperature sensors by union of known types.
# 2. Traverse brick:isPartOf relationships (directly or via a chain) to find VAVs and Zones.

SELECT DISTINCT ?sensor ?sensorLabel ?vav ?vavLabel ?zone ?zoneLabel
WHERE {
  { ?sensor rdf:type brick:Air_Temperature_Sensor. } 
  UNION { ?sensor rdf:type brick:Chilled_Water_Temperature_Sensor. }
  UNION { ?sensor rdf:type brick:Return_Air_Temperature_Sensor. }
  UNION { ?sensor rdf:type brick:Room_Air_Temperature_Sensor. }
  UNION { ?sensor rdf:type brick:Supply_Air_Temperature_Sensor. }
  UNION { ?sensor rdf:type brick:Zone_Air_Temperature_Sensor. }
  OPTIONAL { ?sensor rdfs:label ?sensorLabel. }
  OPTIONAL {
    ?sensor brick:isPartOf+ ?parent .
    ?parent rdf:type brick:VAV .
    BIND(?parent AS ?vav) .
    OPTIONAL { ?vav rdfs:label ?vavLabel. }
  }
  OPTIONAL {
    ?sensor brick:isPartOf+ ?parent2 .
    ?parent2 rdf:type brick:Zone .
    BIND(?parent2 AS ?zone) .
    OPTIONAL { ?zone rdfs:label ?zoneLabel. }
  }
}
ORDER BY ?sensor

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref:   <https://brickschema.org/schema/Brick/ref#>

SELECT DISTINCT ?zoneName ?tsId WHERE {
  # Find zones with IFC names
  ?zone a brick:Zone ;
        brick:hasPart ?space ;
        ref:hasExternalReference ?zoneExt .
  ?zoneExt ref:ifcName ?zoneName .

  # Find minimum air temperature setpoint sensors
  ?minSet a brick:Min_Air_Temperature_Setpoint .
  { ?equip brick:hasPoint    ?minSet }
  UNION
  { ?minSet brick:isPointOf  ?equip }

  # Sensor must be located in one of the zone's spaces
  ?equip brick:hasLocation ?space .

  # Get the sensor's external reference with a timeseries ID
  ?minSet ref:hasExternalReference ?sensorExt .
  ?sensorExt ref:hasTimeseriesId    ?tsId .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref:   <https://brickschema.org/schema/Brick/ref#>
PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?stream_id WHERE {
  {
    # any sensor that is (or is a subclass of) an electrical power sensor
    ?sensor a/rdfs:subClassOf* brick:Electric_Power_Sensor .
  }
  UNION
  {
    # any sensor that is (or is a subclass of) a heat power sensor
    ?sensor a/rdfs:subClassOf* brick:Heat_Power_Sensor .
  }
  # link to its external timeseries reference
  ?sensor ref:hasExternalReference ?xref .
  ?xref a ref:TimeseriesReference ;
        ref:hasTimeseriesId    ?stream_id .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?zone (MAX(?value) AS ?maxTemp) ?unit WHERE {
  ?zone a brick:Zone .

  # Find all max-temperature-setpoint points (including subclasses)
  ?setpoint a/rdfs:subClassOf* brick:Maximum_Air_Temperature_Setpoint ;
            brick:hasValue ?valNode .

  # Get the numeric value and its unit
  ?valNode brick:hasQuantityValue ?value ;
           brick:hasUnit ?unit .

  # Link setpoints to zones either directly or via equipment
  {
    ?zone brick:hasPoint ?setpoint .
  } UNION {
    ?setpoint brick:isPointOf|^brick:hasPoint ?equip .
    ?equip brick:hasLocation ?zone .
  }
}
GROUP BY ?zone ?unit
ORDER BY ?zone

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?point WHERE {
  ?point rdf:type/rdfs:subClassOf* brick:Point .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?sensor ?label WHERE {
  ?sensor rdf:type/rdfs:subClassOf* brick:Temperature_Sensor ;
          brick:hasPointType/rdfs:subClassOf* brick:Supply_Air .
  OPTIONAL { ?sensor rdfs:label ?label }
}

PREFIX ex1: <http://data.ashrae.org/standard223/data/lbnl-example-2#> 
PREFIX s223: <http://data.ashrae.org/standard223#> 
PREFIX qudt: <http://qudt.org/schema/qudt/> 
PREFIX quantitykind: <http://qudt.org/vocab/quantitykind/> 
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#> 

SELECT ?uft ?measurement ?measurementName ?aspect ?value ?unit
WHERE {
  ?uft a ex1:UFT .
  ?uft s223:hasProperty ?measurement .
  ?measurement a s223:QuantifiableObservableProperty .
  ?measurement qudt:hasQuantityKind ?quantityKind .
  FILTER (?quantityKind = quantitykind:VolumeFlowRate || ?quantityKind = quantitykind:HeatFlowRate) .
  OPTIONAL { ?measurement rdfs:label ?measurementName . }
  OPTIONAL { ?measurement s223:hasAspect ?aspect . }
  OPTIONAL { ?measurement s223:hasValue ?value . }
  OPTIONAL { ?measurement qudt:hasUnit ?unit . }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?building ?areaValue ?unit
WHERE {
    ?building a brick:Building .
    ?building brick:area ?areaNode .
    ?areaNode brick:value ?areaValue .
    OPTIONAL { ?areaNode brick:hasUnit ?unit . }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT
    ?zoneLabel
    (GROUP_CONCAT(DISTINCT ?zoneTempSensorId; SEPARATOR=", ") AS ?zoneTemperatureSensorIDs)
    (GROUP_CONCAT(DISTINCT ?minTempSetpointId; SEPARATOR=", ") AS ?minTemperatureSetpointIDs)
    (GROUP_CONCAT(DISTINCT ?maxTempSetpointId; SEPARATOR=", ") AS ?maxTemperatureSetpointIDs)
    (GROUP_CONCAT(DISTINCT ?zoneCoolingTempSetpointId; SEPARATOR=", ") AS ?zoneCoolingTemperatureSetpointIDs)
    (GROUP_CONCAT(DISTINCT ?zoneHeatingTempSetpointId; SEPARATOR=", ") AS ?zoneHeatingTemperatureSetpointIDs)
    (GROUP_CONCAT(DISTINCT ?occupancySensorId; SEPARATOR=", ") AS ?occupancySensorIDs)
    (GROUP_CONCAT(DISTINCT ?occupancyCommandId; SEPARATOR=", ") AS ?occupancyCommandIDs)
    (GROUP_CONCAT(DISTINCT ?vavDamperCommandId; SEPARATOR=", ") AS ?vavDamperCommandIDs)
    (GROUP_CONCAT(DISTINCT ?vavDischargeTempSensorId; SEPARATOR=", ") AS ?vavDischargeTemperatureSensorIDs)
    (GROUP_CONCAT(DISTINCT ?vavReheatCommandId; SEPARATOR=", ") AS ?vavReheatCommandIDs)
WHERE {
    ?zone a brick:HVAC_Zone .
    OPTIONAL { ?zone rdfs:label ?zoneLabel . }

    # Subquery for Zone Temperature Sensor
    OPTIONAL {
        SELECT ?zone ?zoneTempSensorId WHERE {
            ?zone brick:hasPoint ?zoneTempSensor .
            ?zoneTempSensor a brick:Zone_Air_Temperature_Sensor .
            ?zoneTempSensor ref:hasExternalReference ?refZoneTempSensor .
            ?refZoneTempSensor ref:hasTimeseriesId ?zoneTempSensorId .
        }
    }

    # Subquery for Min Temperature Setpoint
    OPTIONAL {
        SELECT ?zone ?minTempSetpointId WHERE {
            ?zone brick:hasPoint ?minTempSetpoint .
            ?minTempSetpoint a brick:Min_Air_Temperature_Setpoint .
            ?minTempSetpoint ref:hasExternalReference ?refMinTempSetpoint .
            ?refMinTempSetpoint ref:hasTimeseriesId ?minTempSetpointId .
        }
    }

    # Subquery for Max Temperature Setpoint
    OPTIONAL {
        SELECT ?zone ?maxTempSetpointId WHERE {
            ?zone brick:hasPoint ?maxTempSetpoint .
            ?maxTempSetpoint a brick:Max_Air_Temperature_Setpoint .
            ?maxTempSetpoint ref:hasExternalReference ?refMaxTempSetpoint .
            ?refMaxTempSetpoint ref:hasTimeseriesId ?maxTempSetpointId .
        }
    }

    # Subquery for Zone Cooling Temperature Setpoint
    OPTIONAL {
        SELECT ?zone ?zoneCoolingTempSetpointId WHERE {
            ?zone brick:hasPoint ?zoneCoolingTempSetpoint .
            ?zoneCoolingTempSetpoint a brick:Zone_Air_Cooling_Temperature_Setpoint .
            ?zoneCoolingTempSetpoint ref:hasExternalReference ?refZoneCoolingTempSetpoint .
            ?refZoneCoolingTempSetpoint ref:hasTimeseriesId ?zoneCoolingTempSetpointId .
        }
    }

    # Subquery for Zone Heating Temperature Setpoint
    OPTIONAL {
        SELECT ?zone ?zoneHeatingTempSetpointId WHERE {
            ?zone brick:hasPoint ?zoneHeatingTempSetpoint .
            ?zoneHeatingTempSetpoint a brick:Zone_Air_Heating_Temperature_Setpoint .
            ?zoneHeatingTempSetpoint ref:hasExternalReference ?refZoneHeatingTempSetpoint .
            ?refZoneHeatingTempSetpoint ref:hasTimeseriesId ?zoneHeatingTempSetpointId .
        }
    }

    # Subquery for Occupancy Sensor
    OPTIONAL {
        SELECT ?zone ?occupancySensorId WHERE {
            ?zone brick:hasPoint ?occupancySensor .
            ?occupancySensor a brick:Occupancy_Sensor .
            ?occupancySensor ref:hasExternalReference ?refOccupancySensor .
            ?refOccupancySensor ref:hasTimeseriesId ?occupancySensorId .
        }
    }

    # Subquery for Occupancy Command
    OPTIONAL {
        SELECT ?zone ?occupancyCommandId WHERE {
            ?zone brick:hasPoint ?occupancyCommand .
            ?occupancyCommand a brick:Occupancy_Command .
            ?occupancyCommand ref:hasExternalReference ?refOccupancyCommand .
            ?refOccupancyCommand ref:hasTimeseriesId ?occupancyCommandId .
        }
    }

    # Subquery for VAV related points
    OPTIONAL {
        SELECT ?zone ?vavDamperCommandId ?vavDischargeTempSensorId ?vavReheatCommandId WHERE {
            ?vav brick:feeds ?zone .
            ?vav a brick:Variable_Air_Volume_Box_With_Reheat .

            OPTIONAL {
                ?vav brick:hasPoint ?vavDamperCommand .
                ?vavDamperCommand a brick:Damper_Position_Setpoint .
                ?vavDamperCommand ref:hasExternalReference ?refVavDamperCommand .
                ?refVavDamperCommand ref:hasTimeseriesId ?vavDamperCommandId .
            }

            OPTIONAL {
                ?vav brick:hasPoint ?vavDischargeTempSensor .
                ?vavDischargeTempSensor a brick:Discharge_Air_Temperature_Sensor .
                ?vavDischargeTempSensor ref:hasExternalReference ?refVavDischargeTempSensor .
                ?refVavDischargeTempSensor ref:hasTimeseriesId ?vavDischargeTempSensorId .
            }

            OPTIONAL {
                ?vav brick:hasPoint ?vavReheatCommand .
                ?vavReheatCommand a brick:Valve_Command .
                ?vavReheatCommand ref:hasExternalReference ?refVavReheatCommand .
                ?refVavReheatCommand ref:hasTimeseriesId ?vavReheatCommandId .
            }
        }
    }
}
GROUP BY ?zone ?zoneLabel
ORDER BY ?zoneLabel

PREFIX brick: <https://brickschema.org/schema/Brick#>
SELECT ?equipment ?sensor
WHERE {
  ?sensor a brick:Supply_Air_Temperature_Sensor .
  ?equipment brick:hasPoint ?sensor .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?entity ?type ?label WHERE {
  {
    ?entity a brick:Electric_Meter .
    BIND("Electric_Meter" AS ?type)
  }
  UNION
  {
    ?entity a brick:Outside_Air_Temperature_Sensor .
    BIND("Outside_Air_Temperature_Sensor" AS ?type)
  }
  OPTIONAL { ?entity rdfs:label ?label }
}
ORDER BY ?type ?entity

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
SELECT ?sensor ?timeseriesId
WHERE {
    {
        ?sensor a brick:Electric_Power_Sensor .
        ?sensor ref:hasExternalReference ?ref .
        ?ref ref:hasTimeseriesId ?timeseriesId .
    }
    UNION
    {
        ?sensor a brick:Thermal_Power_Sensor .
        ?sensor ref:hasExternalReference ?ref .
        ?ref ref:hasTimeseriesId ?timeseriesId .
    }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>

SELECT DISTINCT ?device WHERE {
  ?device brick:hasPoint ?sensor .
  ?sensor a brick:Zone_Air_Temperature_Sensor .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>

SELECT DISTINCT ?ahu ?coolSP ?heatSP WHERE {
  # find AHUs that have both cooling and heating command points
  ?ahu a brick:Air_Handling_Unit ;
       brick:hasPoint ?coolSP, ?heatSP .

  # cooling command point class
  ?coolSP a brick:Supply_Air_Temperature_Setpoint_Cooling .

  # heating command point class
  ?heatSP a brick:Supply_Air_Temperature_Setpoint_Heating .
}

PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX bob: <http://data.ashrae.org/standard223/si-builder#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?uftLabel ?zoneLabel ?ahuLabel WHERE {
  # Find UFT equipment with labels
  ?uft a s223:Equipment ;
       rdfs:label ?uftLabel .

  # Traverse UFT connection path through junctions
  ?uftCP s223:isConnectionPointOf ?uft ;
         s223:cnx+ ?junction .
  ?junction a s223:Junction .

  # Connect through space hierarchy to zone
  ?domainSpace s223:contains* ?junction ;
               s223:contains+ ?zone .
  ?zone a bob:HVACZone ;
        rdfs:label ?zoneLabel .

  # Find AHU through multi-step supply path
  ?ahu a s223:AirHandler ;
       rdfs:label ?ahuLabel .
  ?ahuCP s223:isConnectionPointOf ?ahu ;
         s223:cnx+ ?supplyJunction .

  # Ensure paths converge in domain space
  ?domainSpace s223:contains* ?supplyJunction .
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>

SELECT DISTINCT ?zoneIFCName ?tsid
WHERE {
  ?zone a brick:Zone ;
        ref:hasExternalReference ?zoneRef ;
        brick:hasPart ?space .
  ?zoneRef ref:ifcName ?zoneIFCName .
  ?space brick:isLocationOf ?equip .
  ?equip brick:hasPoint ?tp .
  ?tp a brick:Temperature_Setpoint ;
      ref:hasExternalReference ?tpRef .
  ?tpRef ref:hasTimeseriesId ?tsid .
}

PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX bob: <http://data.ashrae.org/standard223/si-builder#>
PREFIX ref: <https://brickschema.org/schema/Brick/>

SELECT DISTINCT ?propertyLabel ?endpoint ?mpcDbName
WHERE {
    # Find properties directly associated with a Zone or its DomainSpace
    {
        ?zone a s223:Zone .
        { ?zone s223:hasProperty ?property . }
        UNION
        { ?zone s223:hasDomainSpace ?domainSpace . ?domainSpace s223:hasProperty ?property . }
    }
    UNION
    # Find properties of Connectable entities (Equipment, Junctions, etc.) connected to the Zone
    {
        ?zone a s223:Zone .
        ?zone (s223:hasConnectionPoint|bob:hasZoneConnectionPoint) ?zoneCP .

        # Find the Connectable entity that the zone's connection point belongs to
        ?zoneCP s223:isConnectionPointOf ?initialConnectedEntity .

        # Find any Connectable entity that is connected to the initialConnectedEntity
        # This covers "chained connections" by traversing connectedTo/connectedFrom relations via ConnectionPoints
        ?initialConnectedEntity (s223:hasConnectionPoint / (s223:connectedTo|s223:connectedFrom) / s223:isConnectionPointOf)* ?connectedEntity .

        # The connected entity must have the property
        ?connectedEntity s223:hasProperty ?property .
    }

    # Filter for read-only properties and get external reference details
    ?property s223:hasExternalReference ?extRef .
    ?extRef ref:writable "False"^^xsd:boolean .

    OPTIONAL { ?property rdfs:label ?propertyLabel . }
    OPTIONAL { ?extRef ref:endpoint ?endpoint . }
    OPTIONAL { ?extRef ref:mpc_db_name ?mpcDbName . }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>

SELECT DISTINCT ?device
WHERE {
  ?device brick:hasPoint ?reading .
  ?reading a brick:Sensor .
  ?device brick:hasPoint ?config .
  {
    ?config a brick:Command
  } UNION {
    ?config a brick:Setpoint
  }
}

PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX quantitykind: <http://qudt.org/vocab/quantitykind/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?fan ?fanName ?measurement ?measurementName ?aspect ?value ?unit
WHERE {
  # Select unitary fan terminals
  ?fan a s223:FanPoweredTerminal .
  OPTIONAL { ?fan rdfs:label ?fanName . }

  # Get measurement properties attached to the fan terminal
  ?fan s223:hasProperty ?measurement .
  ?measurement qudt:hasQuantityKind ?qkind .
  FILTER(?qkind = quantitykind:VolumeFlowRate || ?qkind = quantitykind:HeatFlowRate)

  OPTIONAL { ?measurement rdfs:label ?measurementName . }
  OPTIONAL { ?measurement s223:hasAspect ?aspect . }
  OPTIONAL { ?measurement s223:hasValue ?value . }
  OPTIONAL { ?measurement qudt:hasUnit ?unit . }
}
ORDER BY ?fanName ?measurementName

PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <http://data.ashrae.org/standard223/si-builder#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

# This query returns properties that are associated with building zones (either directly, via domain spaces,
# or via chained connections) and that are read-only (i.e. their external reference indication for writable
# is false). In order to account for variations in IRIs between Brick and ASHRAE 223p models, we allow for
# zones and property relationships under both s223 and brick namespaces. The writable flag is tested by
# converting the value to lowercase string and casting to a boolean.

SELECT DISTINCT ?zone ?prop ?propLabel ?alcEndpoint ?mpcEndpoint
WHERE {
  {
    # Zones may be typed in either s223 or Brick
    { ?zone a s223:Zone } UNION { ?zone a brick:Zone }

    # Direct association to properties
    { ?zone (s223:hasProperty|brick:hasProperty) ?prop }

  } UNION {
    { ?zone a s223:Zone } UNION { ?zone a brick:Zone }
    ?zone (s223:hasDomainSpace|s223:contains|brick:hasDomainSpace|brick:contains)+ ?intermediate .
    ?intermediate (s223:hasProperty|brick:hasProperty) ?prop .
  } UNION {
    { ?zone a s223:Zone } UNION { ?zone a brick:Zone }
    ?zone (s223:connected|brick:connected)+ ?entity .
    ?entity (s223:hasProperty|brick:hasProperty) ?prop .
  }

  # The property must have an external reference whose writable flag is false.
  ?prop s223:hasExternalReference ?ext .
  ?ext ref:writable ?writable .
  # Convert the writable value to a lowercase string and cast it to xsd:boolean; allow both literal boolean and string forms
  FILTER(xsd:boolean(LCASE(STR(?writable))) = false)

  OPTIONAL { ?prop rdfs:label ?propLabel. }
  OPTIONAL { ?ext ref:endpoint ?alcEndpoint. }
  OPTIONAL { ?ext ref:mpc_db_name ?mpcEndpoint. }
}
ORDER BY ?propLabel

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX ex1: <http://data.ashrae.org/standard223/data/lbnl-example-2#>

# This query finds underfloor distribution devices by their explicit RDF type, determines which thermal zones they serve
# (using the property s223:serves, i.e. the device serves a thermal zone), and from which air handling units they receive air
# (using the property s223:isFedBy to indicate that the device is fed by an AHU).

SELECT DISTINCT ?device ?deviceLabel ?zone ?zoneLabel ?ahu ?ahuLabel
WHERE {
  # Identify underfloor distribution devices using an explicit type
  ?device a s223:UnderfloorDistributionDevice ;
          rdfs:label ?deviceLabel .

  # Find the thermal zones the device serves (direction: device s223:serves zone)
  OPTIONAL {
    ?device s223:serves ?zone .
    ?zone rdfs:label ?zoneLabel .
  }

  # Find the air handling units that supply air to the device (direction: device s223:isFedBy AHU)
  OPTIONAL {
    ?device s223:isFedBy ?ahu .
    ?ahu a s223:AirHandlingUnit ;
         rdfs:label ?ahuLabel .
  }
}
ORDER BY ?deviceLabel ?zoneLabel ?ahuLabel

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?equipment ?sensor ?sensorName ?setpoint ?setpointName
WHERE {
  ?equipment a brick:Equipment .

  ?equipment brick:hasPoint ?sensor .
  ?sensor a brick:Zone_Air_Temperature_Sensor .
  OPTIONAL { ?sensor rdfs:label ?sensorName . }

  ?equipment brick:hasPoint ?setpoint .
  ?setpoint a brick:Zone_Air_Temperature_Setpoint .
  OPTIONAL { ?setpoint rdfs:label ?setpointName . }
}
ORDER BY ?equipment ?sensor ?setpoint

PREFIX bldg1: <urn:bldg/>
PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>

SELECT DISTINCT ?sensor ?timeseriesId
WHERE {
  ?ahu a brick:AHU ;
       brick:hasPoint ?sensor .

  # We are interested in sensors measuring supply air data
  { ?sensor a brick:Supply_Air_Temperature_Sensor } UNION { ?sensor a brick:Supply_Air_Flow_Sensor }.

  # Get the external timeseries reference if available
  OPTIONAL {
    ?sensor ref:hasExternalReference ?ref .
    ?ref ref:hasTimeseriesId ?timeseriesId .
  }
}
ORDER BY ?sensor

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?device ?sensor ?timeseriesId ?onTable ?storedAt
WHERE {
  {
    # Branch for electricity consumption series
    ?sensor a brick:Electric_Power_Sensor .
    ?sensor ref:hasExternalReference ?extRef .
    ?extRef ref:hasTimeseriesId ?timeseriesId .
    OPTIONAL { ?extRef ref:onTable ?onTable . }
    OPTIONAL { ?extRef ref:storedAt ?storedAt . }

    # We select those with timeseriesIds starting with 'chi_rea' which covers series such as "chi_reaPChi_y" and "chi_reaPPumDis_y"
    FILTER(regex(str(?timeseriesId), "^chi_rea", "i"))
    BIND("Electricity Consumption" AS ?device)
  }
  UNION
  {
    # Branch for heating power series
    # Instead of directly querying Electric_Power_Sensor, we follow the heat pump device
    ?heatPump a brick:Pump .
    ?heatPump brick:hasPoint ?sensor .
    ?sensor a brick:Electric_Power_Sensor .
    ?sensor ref:hasExternalReference ?extRef .
    ?extRef ref:hasTimeseriesId ?timeseriesId .
    OPTIONAL { ?extRef ref:onTable ?onTable . }
    OPTIONAL { ?extRef ref:storedAt ?storedAt . }

    # We use a regex that exactly matches the naming convention for the heating pump series
    FILTER(regex(str(?timeseriesId), "^heaPum_reaPHeaPum_y", "i"))
    BIND("Heating Power" AS ?device)
  }
}
ORDER BY ?device ?sensor

PREFIX ex1: <http://data.ashrae.org/standard223/data/lbnl-example-2#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?uft ?label
WHERE {
  { ?uft a ex1:UFT_HWC_Valve .
    ?uft rdfs:label ?label .
  }
  UNION
  { ?uft a ex1:UFT_Fan .
    ?uft rdfs:label ?label .
  }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>

SELECT DISTINCT ?point
WHERE {
  { ?s brick:hasPoint ?point . }
  UNION
  { ?point a brick:Point . }
}

PREFIX bldg1: <urn:bldg/>
PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?zone ?zoneName
       (GROUP_CONCAT(DISTINCT ?tempSensorTsId; SEPARATOR=", ") AS ?temperatureMeasurements)
       (GROUP_CONCAT(DISTINCT ?minTempSpTsId; SEPARATOR=", ") AS ?minTemperatureSetpoints)
       (GROUP_CONCAT(DISTINCT ?maxTempSpTsId; SEPARATOR=", ") AS ?maxTemperatureSetpoints)
       (GROUP_CONCAT(DISTINCT ?heatingTempSpTsId; SEPARATOR=", ") AS ?heatingTemperatureSetpoints)
       (GROUP_CONCAT(DISTINCT ?coolingTempSpTsId; SEPARATOR=", ") AS ?coolingTemperatureSetpoints)
       (GROUP_CONCAT(DISTINCT ?occupiedTempSpTsId; SEPARATOR=", ") AS ?occupiedTemperatureSetpoints)
       (GROUP_CONCAT(DISTINCT ?unoccupiedTempSpTsId; SEPARATOR=", ") AS ?unoccupiedTemperatureSetpoints)
       (GROUP_CONCAT(DISTINCT ?occupancySensorTsId; SEPARATOR=", ") AS ?occupancySensing)
       (GROUP_CONCAT(DISTINCT ?occupancyCommandTsId; SEPARATOR=", ") AS ?occupancyCommand)
       (GROUP_CONCAT(DISTINCT ?damperPositionTsId; SEPARATOR=", ") AS ?damperPosition)
       (GROUP_CONCAT(DISTINCT ?dischargeTempTsId; SEPARATOR=", ") AS ?dischargeTemperature)
       (GROUP_CONCAT(DISTINCT ?reheatControlTsId; SEPARATOR=", ") AS ?reheatControlSignals)
WHERE {
    ?zone a brick:HVAC_Zone .
    ?zone rdfs:label ?zoneName .

    # Points typically associated with a Thermostat controlling the zone
    OPTIONAL {
        ?thermostat brick:controls ?zone .

        # Temperature Measurements
        OPTIONAL {
            ?thermostat brick:hasPoint ?tempSensor .
            ?tempSensor a brick:Temperature_Sensor .
            ?tempSensor ref:hasTimeseriesId ?tempSensorTsId .
        }

        # Setpoint Targets
        OPTIONAL {
            ?thermostat brick:hasPoint ?minTempSp .
            ?minTempSp a brick:Min_Temperature_Setpoint .
            ?minTempSp ref:hasTimeseriesId ?minTempSpTsId .
        }
        OPTIONAL {
            ?thermostat brick:hasPoint ?maxTempSp .
            ?maxTempSp a brick:Max_Temperature_Setpoint .
            ?maxTempSp ref:hasTimeseriesId ?maxTempSpTsId .
        }
        OPTIONAL {
            ?thermostat brick:hasPoint ?heatingTempSp .
            ?heatingTempSp a brick:Heating_Temperature_Setpoint .
            ?heatingTempSp ref:hasTimeseriesId ?heatingTempSpTsId .
        }
        OPTIONAL {
            ?thermostat brick:hasPoint ?coolingTempSp .
            ?coolingTempSp a brick:Cooling_Temperature_Setpoint .
            ?coolingTempSp ref:hasTimeseriesId ?coolingTempSpTsId . # Corrected variable name
        }
        OPTIONAL {
            ?thermostat brick:hasPoint ?occupiedTempSp .
            ?occupiedTempSp a brick:Occupied_Temperature_Setpoint .
            ?occupiedTempSp ref:hasTimeseriesId ?occupiedTempSpTsId .
        }
        OPTIONAL {
            ?thermostat brick:hasPoint ?unoccupiedTempSp .
            ?unoccupiedTempSp a brick:Unoccupied_Temperature_Setpoint .
            ?unoccupiedTempSp ref:hasTimeseriesId ?unoccupiedTempSpTsId .
        }

        # Occupancy Sensing and Command
        OPTIONAL {
            ?thermostat brick:hasPoint ?occupancySensor .
            ?occupancySensor a brick:Occupancy_Sensor .
            ?occupancySensor ref:hasTimeseriesId ?occupancySensorTsId .
        }
        OPTIONAL {
            ?thermostat brick:hasPoint ?occupancyCommand .
            ?occupancyCommand a brick:Occupancy_Command .
            ?occupancyCommand ref:hasTimeseriesId ?occupancyCommandTsId .
        }
    }

    # VAV Unit related points (linked via serves relationship)
    OPTIONAL {
        ?vav a brick:VAV .
        ?vav brick:serves ?zone .

        # Damper Position
        OPTIONAL {
            ?vav brick:hasPoint ?damperPositionPoint .
            ?damperPositionPoint a brick:Damper_Position_Sensor .
            ?damperPositionPoint ref:hasTimeseriesId ?damperPositionTsId .
        }
        # Discharge Temperature
        OPTIONAL {
            ?vav brick:hasPoint ?dischargeTempPoint .
            ?dischargeTempPoint a brick:Discharge_Air_Temperature_Sensor .
            ?dischargeTempPoint ref:hasTimeseriesId ?dischargeTempTsId .
        }
        # Reheat Control Signals
        OPTIONAL {
            ?vav brick:hasPoint ?reheatControlPoint .
            ?reheatControlPoint a brick:Reheat_Command .
            ?reheatControlPoint ref:hasTimeseriesId ?reheatControlTsId .
        }
    }
} 
GROUP BY ?zone ?zoneName
ORDER BY ?zoneName

PREFIX ex1: <http://data.ashrae.org/standard223/data/lbnl-example-2#>
PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX quantitykind: <http://qudt.org/vocab/quantitykind/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?uft ?uftLabel ?property ?propLabel ?aspect ?value ?unit
WHERE {
  # Identify UFT devices by filtering their rdf:type for "UFT" in the URI (case-insensitive)
  ?uft a ?uftType .
  FILTER(regex(str(?uftType), "UFT", "i")) .
  OPTIONAL { ?uft rdfs:label ?uftLabel. }

  # Assume that the UFT's measurable properties are attached via the s223:hasProperty relation
  ?uft s223:hasProperty ?property .

  # Consider only those properties that are quantified with a quantity kind of volume flow rate or heat flow rate
  ?property qudt:hasQuantityKind ?qkind .
  FILTER(?qkind = quantitykind:VolumeFlowRate || ?qkind = quantitykind:HeatFlowRate) .

  OPTIONAL { ?property rdfs:label ?propLabel. }
  OPTIONAL { ?property s223:hasAspect ?aspect. }
  OPTIONAL { ?property s223:hasValue ?value. }
  OPTIONAL { ?property qudt:hasUnit ?unit. }
}
ORDER BY ?uft ?propLabel

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX bf: <https://brickschema.org/schema/BrickFrame#>
SELECT ?zone ?setpoint ?timeseries WHERE {
    ?zone a brick:Zone .
    ?equipment brick:serves ?zone .
    ?equipment bf:hasPoint ?setpoint .
    ?setpoint a brick:Peak_Temperature_Setpoint .
    OPTIONAL {
        ?setpoint bf:hasTimeseries ?timeseries .
    }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?device
WHERE {
    ?sensor rdf:type brick:Temperature_Sensor .
    ?zone rdf:type brick:Zone .

    {
        ?sensor brick:hasLocation ?zone .
    }
    UNION
    {
        ?sensor brick:isPointOf ?equipment .
        ?equipment brick:hasLocation ?zone .
    }

    {
        BIND(?sensor AS ?device) .
    }
    UNION
    {
        ?device brick:hasPart ?sensor .
    }
    UNION
    {
        ?device brick:hasPoint ?sensor .
    }

    FILTER EXISTS { ?device rdf:type brick:Device }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?device (GROUP_CONCAT(DISTINCT ?sensor; SEPARATOR=", ") AS ?sensors) (GROUP_CONCAT(DISTINCT ?controlValue; SEPARATOR=", ") AS ?controlValues)
WHERE {
  ?device a ?deviceType .
  ?deviceType rdfs:subClassOf* brick:Equipment .

  OPTIONAL {
    ?device brick:hasPoint ?sensor .
    ?sensor a ?sensorType .
    ?sensorType rdfs:subClassOf* brick:Sensor .
  }

  OPTIONAL {
    ?device brick:hasPoint ?controlValue .
    ?controlValue a ?controlValueType .
    { ?controlValueType rdfs:subClassOf* brick:Command } 
    UNION 
    { ?controlValueType rdfs:subClassOf* brick:Setpoint }
  }
}
GROUP BY ?device

PREFIX bldg1: <urn:bldg/>
PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?timeseriesId
WHERE {
    ?point a brick:Point .
    {
        ?point a brick:Power_Sensor .
    }
    UNION
    {
        ?point brick:hasTag brick:Power .
    }

    ?point ref:hasTimeseriesId ?timeseriesId .
    FILTER (CONTAINS(STR(?timeseriesId), "flexible_"))
}

PREFIX bldg1: <urn:bldg/>
PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?building ?areaType ?areaValue ?unit WHERE {
  ?building a brick:Building .
  ?building brick:hasPoint ?areaPoint .
  ?areaPoint a ?areaType .
  VALUES ?areaType { brick:GrossFloorArea brick:FootprintArea }
  ?areaPoint brick:hasValue ?areaValue .
  OPTIONAL { ?areaPoint brick:hasUnit ?unit . }
}

PREFIX bldg1: <urn:bldg/>
PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT DISTINCT ?powerMeasurementSeries
WHERE {
    ?powerMeasurementSeries a ?pointType .
    {
        ?pointType rdfs:subClassOf* brick:Power_Sensor .
    }
    UNION
    {
        ?pointType rdfs:subClassOf* brick:Power_Meter .
    }
}

PREFIX bacnet: <http://data.ashrae.org/bacnet/2020#>
PREFIX bob: <http://data.ashrae.org/standard223/si-builder#>
PREFIX ex1: <http://data.ashrae.org/standard223/data/lbnl-example-2#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX quantitykind: <http://qudt.org/vocab/quantitykind/>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ref: <https://brickschema.org/schema/Brick/>
PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX sh: <http://www.w3.org/ns/shacl#>
PREFIX unit: <http://qudt.org/vocab/unit/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?heatPump ?pointOrParameter ?attribute ?readOnlyControlAddress ?databaseAddress ?bacnetAddress
WHERE {
    ?heatPump rdf:type s223:Water_to_Water_Heat_Pump .
    {
        ?heatPump s223:hasPoint ?pointOrParameter .
    } UNION {
        ?heatPump s223:hasParameter ?pointOrParameter .
    }
    ?pointOrParameter s223:hasAttribute ?attribute .
    OPTIONAL { ?pointOrParameter s223:hasReadOnlyControlAddress ?readOnlyControlAddress . }
    OPTIONAL { ?pointOrParameter s223:hasDatabaseAddress ?databaseAddress . }
    OPTIONAL {
        ?pointOrParameter s223:representsBACnetObject ?bacnetObject .
        ?bacnetObject bacnet:objectIdentifier ?bacnetAddress .
    }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?entity
WHERE {
  {
    ?entity rdf:type/rdfs:subClassOf* brick:Meter .
  }
  UNION
  {
    ?entity rdf:type/rdfs:subClassOf* brick:Weather_Sensor .
  }
}

PREFIX bacnet: <http://data.ashrae.org/bacnet/2020#>
PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX bsh: <https://brickschema.org/schema/BrickShape#>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX ns2: <http://buildsys.org/ontologies/bldg11#>
PREFIX ns3: <http://buildsys.org/ontologies/bldg11#bldg11.CHW.Pump1_Start/>
PREFIX ns4: <http://buildsys.org/ontologies/bldg11#bldg11.CHW.Pump2_Start/>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX qudtqk: <http://qudt.org/vocab/quantitykind/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX rec: <https://w3id.org/rec#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX sdo: <http://schema.org/>
PREFIX sh: <http://www.w3.org/ns/shacl#>
PREFIX skos: <http://www.w3.org/2004/02/skos/core#>
PREFIX sosa: <http://www.w3.org/ns/sosa#>
PREFIX tag: <https://brickschema.org/schema/BrickTag#>
PREFIX unit: <http://qudt.org/vocab/unit/>
PREFIX vcard: <http://www.w3.org/2006/vcard/ns#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT DISTINCT ?controlPoint ?ahu
WHERE {
    ?ahu rdf:type brick:Air_Handling_Unit .
    ?ahu brick:hasPoint ?controlPoint .
    ?controlPoint rdf:type brick:Control_Point .

    {
        # Case 1: The control point itself is a Cooling_Point or Heating_Point
        # (e.g., a Cooling_Valve_Command, which is a Control_Point and a Cooling_Point)
        ?controlPoint rdf:type ?pointType .
        {
            ?pointType rdfs:subClassOf* brick:Cooling_Point .
        } UNION {
            ?pointType rdfs:subClassOf* brick:Heating_Point .
        }
    } UNION {
        # Case 2: The control point controls another point that is a Cooling_Point or Heating_Point
        # (e.g., a PID_Control controlling a Cooling_Temperature_Setpoint or Cooling_Valve_Command)
        ?controlPoint brick:controls ?controlledPoint .
        ?controlledPoint rdf:type ?controlledPointType .
        {
            ?controlledPointType rdfs:subClassOf* brick:Cooling_Point .
        } UNION {
            ?controlledPointType rdfs:subClassOf* brick:Heating_Point .
        }
    } UNION {
        # Case 3: The control point controls a component that is a Cooling_Coil or Heating_Coil
        # (less common for direct control, but possible depending on modeling)
        ?controlPoint brick:controls ?controlledComponent .
        ?controlledComponent rdf:type ?componentType .
        {
            ?componentType rdfs:subClassOf* brick:Cooling_Coil .
        } UNION {
            ?componentType rdfs:subClassOf* brick:Heating_Coil .
        }
    }
}

PREFIX bacnet: <http://data.ashrae.org/bacnet/2020#>
PREFIX bob: <http://data.ashrae.org/standard223/si-builder#>
PREFIX ex1: <http://data.ashrae.org/standard223/data/lbnl-example-2#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX quantitykind: <http://qudt.org/vocab/quantitykind/>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ref: <https://brickschema.org/schema/Brick/>
PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX sh: <http://www.w3.org/ns/shacl#>
PREFIX unit: <http://qudt.org/vocab/unit/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT DISTINCT ?prop ?label ?alcEndpoint ?mpcEndpoint
WHERE {
    {
        ?zone a s223:BuildingZone .
        ?zone s223:hasProperty ?prop .
    }
    UNION
    {
        ?zone a s223:BuildingZone .
        ?zone s223:hasPart ?room .
        ?room a s223:RoomDomainSpace .
        ?room s223:hasProperty ?prop .
    }
    UNION
    {
        ?zone a s223:BuildingZone .
        ?zone s223:hasPart ?room .
        ?room a s223:RoomDomainSpace .
        ?room s223:hasConnection ?conn .
        ?conn a s223:ChainedConnection .
        ?conn s223:hasProperty ?prop .
    }
    UNION
    {
        ?zone a s223:BuildingZone .
        ?zone s223:hasConnection ?conn .
        ?conn a s223:ChainedConnection .
        ?conn s223:hasProperty ?prop .
    }

    ?prop s223:isWritable "false"^^xsd:boolean .
    OPTIONAL { ?prop rdfs:label ?label . }
    OPTIONAL {
        ?prop s223:hasExternalReference ?extRef .
        OPTIONAL { ?extRef s223:alcEndpoint ?alcEndpoint . }
        OPTIONAL { ?extRef s223:mpcEndpoint ?mpcEndpoint . }
    }
}

PREFIX brick: <https://brickschema.org/schema/Brick#>
SELECT ?entity WHERE {
  ?building a brick:Building .
  {
    ?entity a brick:Building_Electrical_Meter .
    ?entity brick:isLocationOf ?building .
  }
  UNION
  {
    ?entity a brick:Outside_Air_Temperature_Sensor .
    ?building brick:hasPart* ?entity .
  }
}

PREFIX brick: <https://brickschema.org/schema/1.0.3/Brick#>
PREFIX as: <http://www.asme.org/standards/ASHRAE223P#>

SELECT ?zoneName ?tsID
WHERE {
  ?zone a brick:Zone ;
        brick:name ?zoneName .
  # Retrieve the high temperature setpoint either directly from the zone or from equipment serving the zone
  { ?zone brick:hasPoint ?sp . }
  UNION
  { ?equip brick:serves ?zone ;
           brick:hasPoint ?sp . }

  ?sp a brick:High_Temperature_Setpoint .
  ?sp brick:hasTimeseries ?ts .
  # Try both possible properties for the timeseries identifier
  ?ts (brick:identifier|brick:hasTag) ?tsID .
}

PREFIX brick: <https://brickschema.org/schema/Brick#> 
SELECT ?entity ?type 
WHERE { 
  ?entity a ?type . 
  FILTER (?type = brick:Point || ?type = brick:Sensor || ?type = brick:Actuator) 
}

PREFIX bldg1: <urn:bldg/>
PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ref: <https://brickschema.org/schema/Brick/ref#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT DISTINCT ?zone ?dataStream ?dataType
WHERE {
  ?zone a brick:Zone .

  # Support various relationships linking zones to their monitoring/control points
  { ?zone brick:hasPoint ?dataStream . }
  UNION { ?zone brick:hasSensor ?dataStream . }
  UNION { ?zone brick:hasMonitoringPoint ?dataStream . }
  UNION { ?zone brick:hasControlPoint ?dataStream . }
  UNION { ?dataStream brick:isPointOf ?zone . }

  # Match the types allowing for subclassing
  ?dataStream a ?actualType .

  # Define the set of candidate classes and their corresponding label
  VALUES (?pointClass ?dataType) {
    (brick:Temperature_Sensor "temperature")
    (brick:Temperature_Setpoint "setpoints")
    (brick:Occupancy_Sensor "occupancy")
    (brick:VAV_Control "VAV controls")
  }

  # Allow matching via subclass relationships
  ?actualType rdfs:subClassOf* ?pointClass .
}

PREFIX brick: <https://brickschema.org/schema/brick#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?zoneLabel ?dataStreamID
WHERE {
  ?zone a brick:Zone ;
        rdfs:label ?zoneLabel .

  ?sensor a brick:Occupancy_Sensor ;
          brick:monitors ?zone ;
          brick:hasPoint ?point .

  ?point brick:dataStreamID ?dataStreamID .
}
ORDER BY ?zoneLabel

PREFIX bacnet: <http://data.ashrae.org/bacnet/2020#>
PREFIX bob: <http://data.ashrae.org/standard223/si-builder#>
PREFIX ex1: <http://data.ashrae.org/standard223/data/lbnl-example-2#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX quantitykind: <http://qudt.org/vocab/quantitykind/>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ref: <https://brickschema.org/schema/Brick/>
PREFIX s223: <http://data.ashrae.org/standard223#>
PREFIX sh: <http://www.w3.org/ns/shacl#>
PREFIX unit: <http://qudt.org/vocab/unit/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

# This query is improved via alternative matching strategies. It looks for fan terminals
# and, via the property ref:hasPoint, retrieves measurement points that could represent
# volumetric flow data (by matching either a sensor type or by a QUDT quantityKind) as well as
# heat flow data. The UNION clauses allow matching one of two patterns in each optional block.

SELECT DISTINCT ?fan ?volumePoint ?heatFlowPoint
WHERE {
  ?fan rdf:type ref:Fan_Terminal .

  OPTIONAL {
    ?fan ref:hasPoint ?volumePoint .
    {
      ?volumePoint rdf:type ref:Air_Flow_Sensor .
    } UNION {
      ?volumePoint qudt:quantityKind quantitykind:VolumetricFlow .
    }
  }

  OPTIONAL {
    ?fan ref:hasPoint ?heatFlowPoint .
    {
      ?heatFlowPoint rdf:type ref:Heat_Flow_Meter .
    } UNION {
      ?heatFlowPoint qudt:quantityKind quantitykind:HeatFlowRate .
    }
  }
}

PREFIX brick: <https://brickschema.org/schema/1.1/Brick#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX ashrae: <https://buildingsmart.org/ASHRAE223p#>

SELECT ?zone ?ifcName ?tsid
WHERE {
  # Identify zones with an IFC name that have parts (spaces)
  ?zone a brick:Zone ;
        brick:ifcName ?ifcName ;
        brick:hasPart ?space .
  ?space a brick:Space .

  # Traverse from zone to sensor through the space using a property path
  ?zone brick:hasPart/brick:isLocatedIn ?sensor .

  # Sensor must be one of several possible types
  VALUES ?sensorType {
    brick:MinimumAirTemperatureSetpointSensor
    ashrae:MinimumAirTemperatureSetpointSensor
    brick:Air_Temperature_Setpoint_Sensor
  }.
  ?sensor a ?sensorType .

  # The sensor is associated with a timeseries which carries the timeseries ID. We allow either Brick or ASHRAE property usage.
  {
    ?sensor brick:hasTimeseries ?ts .
    ?ts ashrae:timeseriesID ?tsid .
  } UNION {
    ?sensor ashrae:hasTimeseries ?ts .
    ?ts ashrae:timeseriesID ?tsid .
  }
}

PREFIX brick: <https://brickschema.org/schema/Brick#> 
PREFIX sosa: <http://www.w3.org/ns/sosa/> 
PREFIX bsh: <https://brickschema.org/schema/BrickShape#> 
SELECT ?meter ?recorder 
WHERE { 
  ?meter a brick:Electricity_Usage_Meter ; 
         bsh:locatedIn ?location . 
  ?recorder a brick:Temperature_Sensor ; 
             sosa:observes ?oat ; 
             bsh:locatedIn ?location . 
  ?oat a brick:Outside_Air_Temperature . 
}

PREFIX bob:   <http://data.ashrae.org/standard223/si-builder#>
PREFIX s223:  <http://data.ashrae.org/standard223#>
PREFIX brick: <https://brickschema.org/schema/Brick#>
PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?prop ?label ?alc ?mpc WHERE {
  # 1) HVAC zones
  ?zone a bob:HVACZone .

  # 2) Properties on the zone, on its domain spaces, or via transitive connectsTo
  { ?zone s223:hasProperty    ?prop }
  UNION
  { ?zone s223:hasDomainSpace ?space .
    ?space s223:hasProperty    ?prop }
  UNION
  { ?zone s223:connectsTo*    ?inter .
    ?inter s223:hasProperty    ?prop }

  # 3) Only read­-only points: tagged Readable but not Writable
  ?prop brick:hasTag     brick:Tag_Readable .
  FILTER NOT EXISTS { ?prop brick:hasTag brick:Tag_Writable }

  # 4) Optional human label
  OPTIONAL { ?prop rdfs:label ?label }

  # 5) ALC and MPC endpoints from external refs
  OPTIONAL {
    ?prop s223:hasExternalRef ?xref .
    OPTIONAL { ?xref s223:alcEndpoint ?alc }
    OPTIONAL { ?xref s223:mpcEndpoint ?mpc }
  }
}
